import { Command } from "commander";
import fs from "fs-extra";
import path from "path";
import { fileURLToPath } from "url";
import chalk from "chalk";
import WatcherService from "../index.js";
import { createCorrectorRegistry } from "../trigger/correctors.js";
import {
  preventionConfigSchema,
  triggerConfigSchema,
  validateConfig,
} from "../shared/config-schema.js";
import logger from "../shared/logger.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const pkg = fs.readJsonSync(path.join(__dirname, "../../package.json"));

/**
 * CLI interface for the Watcher Service
 */
export class WatcherCLI {
  private service: WatcherService;
  private program: Command;

  constructor() {
    this.service = new WatcherService();
    this.program = new Command();

    this.setupCLI();
  }

  private setupCLI(): void {
    this.program
      .name("watcher")
      .description(
        chalk.blue("File watcher service") +
          " for surveillance, prevention, and automatic correction"
      )
      .version(pkg.version);

    this.setupStartCommand();
    this.setupStopCommand();
    this.setupStatusCommand();
    this.setupReloadCommand();
    this.setupTestCommand();
    this.setupConfigCommand();
    this.setupTestAllCommand();
    this.setupPreviewCommand();
  }

  private setupStartCommand(): void {
    this.program
      .command("start")
      .description("Start the watcher service")
      .option(
        "-d, --dir <directory>",
        "Directory to watch",
        process.env.WATCH_DIR || process.cwd()
      )
      .option("--no-prevention", "Disable prevention module")
      .option("--no-trigger", "Disable trigger module")
      .action(async (options) => {
        try {
          console.log(chalk.blue("ÔûÂ") + " Starting Watcher Service...");

          this.service = new WatcherService({
            watchDir: options.dir,
            enablePrevention: options.prevention,
            enableTrigger: options.trigger,
          });

          await this.service.initialize();
          await this.service.start();

          console.log(
            chalk.green("Ô£ö") +
              " Watcher Service " +
              chalk.bold("started") +
              " on " +
              chalk.cyan(options.dir)
          );
          console.log(
            chalk.gray(
              "  Prevention: " +
                (options.prevention ? chalk.green("ON") : chalk.red("OFF"))
            )
          );
          console.log(
            chalk.gray(
              "  Trigger:    " +
                (options.trigger ? chalk.green("ON") : chalk.red("OFF"))
            )
          );
          console.log(chalk.gray("  Press Ctrl+C to stop."));

          process.on("SIGINT", async () => {
            console.log(chalk.yellow("\nÔÅ╣") + " Stopping service...");
            await this.service.stop();
            this.printMetrics();
            process.exit(0);
          });

          process.on("SIGTERM", async () => {
            await this.service.stop();
            process.exit(0);
          });
        } catch (error) {
          console.error(chalk.red("Ô£û") + " Error starting service:", error);
          process.exit(1);
        }
      });
  }

  private setupStopCommand(): void {
    this.program
      .command("stop")
      .description("Stop the watcher service")
      .action(async () => {
        try {
          await this.service.stop();
          console.log(chalk.green("Ô£ö") + " Watcher Service stopped");
        } catch (error) {
          console.error(chalk.red("Ô£û") + " Error stopping service:", error);
          process.exit(1);
        }
      });
  }

  private setupStatusCommand(): void {
    this.program
      .command("status")
      .description("Show watcher service status")
      .option("--json", "Output as JSON")
      .action((options) => {
        const status = this.service.getStatus();

        if (options.json) {
          console.log(JSON.stringify(status, null, 2));
          return;
        }

        console.log(chalk.bold("\nWatcher Service Status\n"));
        console.log(
          "  " +
            chalk.gray("Initialized:") +
            " " +
            (status.initialized ? chalk.green("Ô£ö Yes") : chalk.red("Ô£û No"))
        );
        console.log(
          "  " +
            chalk.gray("Running:") +
            " " +
            (status.running ? chalk.green("Ô£ö Yes") : chalk.red("Ô£û No"))
        );

        if (status.metrics.startTime) {
          console.log(
            "  " +
              chalk.gray("Started at:") +
              " " +
              chalk.cyan(status.metrics.startTime.toISOString())
          );
        }

        console.log(chalk.bold("\n  Metrics\n"));
        console.log(
          "  " +
            chalk.gray("Files processed:") +
            " " +
            chalk.cyan(String(status.metrics.filesProcessed))
        );
        console.log(
          "  " +
            chalk.gray("Files corrected:") +
            " " +
            chalk.green(String(status.metrics.filesCorrected))
        );
        console.log(
          "  " +
            chalk.gray("Files failed:") +
            " " +
            chalk.red(String(status.metrics.filesFailed))
        );
        if (status.metrics.totalProcessingTime > 0) {
          const avg =
            status.metrics.filesProcessed > 0
              ? Math.round(
                  status.metrics.totalProcessingTime /
                    status.metrics.filesProcessed
                )
              : 0;
          console.log(
            "  " +
              chalk.gray("Avg processing time:") +
              " " +
              chalk.cyan(`${avg}ms`)
          );
        }

        console.log(chalk.bold("\n  Modules\n"));
        for (const [name, modStatus] of Object.entries(status.modules)) {
          const state =
            modStatus && typeof modStatus === "object" && "running" in modStatus
              ? Boolean(modStatus.running)
              : false;
          console.log(
            "  " +
              chalk.gray(`${name}:`) +
              " " +
              (state ? chalk.green("Ô£ö Running") : chalk.red("Ô£û Stopped"))
          );
        }
        console.log();
      });
  }

  private setupReloadCommand(): void {
    this.program
      .command("reload")
      .description("Reload configuration")
      .action(async () => {
        try {
          await this.service.reloadConfig();
          console.log(chalk.green("Ô£ö") + " Configuration reloaded");
        } catch (error) {
          console.error(
            chalk.red("Ô£û") + " Error reloading configuration:",
            error
          );
          process.exit(1);
        }
      });
  }

  private setupTestCommand(): void {
    this.program
      .command("test")
      .description("Test the watcher service with a sample file")
      .option("-f, --file <file>", "File to test with")
      .action(async (options) => {
        try {
          if (!options.file) {
            console.error(
              chalk.red("Ô£û") +
                " Please specify a file to test with: " +
                chalk.bold("--file <file>")
            );
            process.exit(1);
          }

          if (!fs.existsSync(options.file)) {
            console.error(
              chalk.red("Ô£û") + " File not found: " + chalk.bold(options.file)
            );
            process.exit(1);
          }

          await this.service.initialize();

          console.log(
            chalk.blue("ÔûÂ") + " Testing with file: " + chalk.cyan(options.file)
          );

          const startTime = Date.now();
          const testResult = await this.service
            .getPreventionModule()
            ?.processFile(options.file);
          const duration = Date.now() - startTime;

          if (!testResult) {
            console.log(chalk.yellow("ÔÜá") + " Prevention module not available");
            return;
          }

          console.log(chalk.gray(`  Completed in ${duration}ms\n`));

          if (testResult.success) {
            console.log(chalk.green("Ô£ö") + " Validation passed");
          } else {
            console.log(chalk.red("Ô£û") + " Validation failed");
          }

          if (testResult.errors && testResult.errors.length > 0) {
            console.log(chalk.red("\n  Errors:"));
            for (const err of testResult.errors) {
              console.log("    " + chalk.red("ÔÇó") + " " + err);
            }
          }

          if (testResult.warnings && testResult.warnings.length > 0) {
            console.log(chalk.yellow("\n  Warnings:"));
            for (const warn of testResult.warnings) {
              console.log("    " + chalk.yellow("ÔÇó") + " " + warn);
            }
          }

          if (testResult.metadata) {
            console.log(
              chalk.gray("\n  Metadata:") +
                " " +
                JSON.stringify(testResult.metadata, null, 2)
            );
          }
          console.log();
        } catch (error) {
          console.error(chalk.red("Ô£û") + " Error in test:", error);
          process.exit(1);
        }
      });
  }

  private setupConfigCommand(): void {
    this.program
      .command("config")
      .description("Validate and display current configuration")
      .option("--validate", "Validate config files only")
      .option("--prevention <path>", "Path to prevention config file")
      .option("--trigger <path>", "Path to trigger config file")
      .action(async (options) => {
        try {
          const preventionPath =
            options.prevention ||
            path.join(process.cwd(), "config", "prevention-rules.json");
          const triggerPath =
            options.trigger ||
            path.join(process.cwd(), "config", "trigger-rules.json");

          console.log(chalk.bold("\nConfiguration Validation\n"));

          let hasErrors = false;

          // Validate prevention config
          console.log(
            chalk.gray("Prevention config: ") + chalk.cyan(preventionPath)
          );
          if (fs.existsSync(preventionPath)) {
            const preventionConfig = fs.readJsonSync(preventionPath);
            const result = validateConfig(
              preventionConfig,
              preventionConfigSchema
            );
            if (result.valid) {
              console.log(
                "  " +
                  chalk.green("Ô£ö") +
                  " Valid" +
                  (result.warnings.length > 0
                    ? chalk.yellow(` (${result.warnings.length} warnings)`)
                    : "")
              );
              if (!options.validate) {
                console.log(
                  "    " +
                    chalk.gray("Rules: ") +
                    chalk.cyan(String(preventionConfig.rules?.length || 0))
                );
                const enabled =
                  preventionConfig.rules?.filter((r: any) => r.enabled)
                    .length || 0;
                console.log(
                  "    " +
                    chalk.gray("Enabled: ") +
                    chalk.green(String(enabled))
                );
              }
            } else {
              hasErrors = true;
              console.log("  " + chalk.red("Ô£û Invalid"));
              for (const err of result.errors) {
                console.log("    " + chalk.red("ÔÇó") + " " + err);
              }
            }
          } else {
            console.log("  " + chalk.yellow("ÔÜá File not found"));
          }

          // Validate trigger config
          console.log(
            chalk.gray("\nTrigger config:    ") + chalk.cyan(triggerPath)
          );
          if (fs.existsSync(triggerPath)) {
            const triggerConfig = fs.readJsonSync(triggerPath);
            const result = validateConfig(triggerConfig, triggerConfigSchema);
            if (result.valid) {
              console.log(
                "  " +
                  chalk.green("Ô£ö") +
                  " Valid" +
                  (result.warnings.length > 0
                    ? chalk.yellow(` (${result.warnings.length} warnings)`)
                    : "")
              );
              if (!options.validate) {
                console.log(
                  "    " +
                    chalk.gray("Rules: ") +
                    chalk.cyan(String(triggerConfig.rules?.length || 0))
                );
                const enabled =
                  triggerConfig.rules?.filter((r: any) => r.enabled).length ||
                  0;
                console.log(
                  "    " +
                    chalk.gray("Enabled: ") +
                    chalk.green(String(enabled))
                );
              }
            } else {
              hasErrors = true;
              console.log("  " + chalk.red("Ô£û Invalid"));
              for (const err of result.errors) {
                console.log("    " + chalk.red("ÔÇó") + " " + err);
              }
            }
          } else {
            console.log("  " + chalk.yellow("ÔÜá File not found"));
          }

          console.log();

          if (hasErrors) {
            process.exit(1);
          }
        } catch (error) {
          console.error(chalk.red("Ô£û") + " Error validating config:", error);
          process.exit(1);
        }
      });
  }

  private setupTestAllCommand(): void {
    this.program
      .command("test-all")
      .description("Test the full pipeline with a sample file")
      .option("-d, --dir <directory>", "Directory to watch", process.cwd())
      .option("-f, --file <file>", "Specific file to test")
      .action(async (options) => {
        try {
          console.log(chalk.bold("\nFull Pipeline Test\n"));

          // Create a temp test file if no file specified
          let testFile = options.file;
          let cleanupNeeded = false;

          if (!testFile) {
            const tmpDir = path.join(
              process.env.TEMP || process.env.TMP || "/tmp",
              "watcher-test"
            );
            await fs.ensureDir(tmpDir);
            testFile = path.join(tmpDir, "test-pipeline.ts");
            await fs.writeFile(
              testFile,
              'const x: string = "hello";\nconsole.log(x);\n'
            );
            cleanupNeeded = true;
            console.log(
              chalk.gray("  Created test file: ") + chalk.cyan(testFile)
            );
          } else if (!fs.existsSync(testFile)) {
            console.error(
              chalk.red("Ô£û") + " File not found: " + chalk.bold(testFile)
            );
            process.exit(1);
          }

          // Step 1: Initialize service
          console.log(
            chalk.blue("\n1.") + chalk.bold(" Initializing modules...")
          );
          this.service = new WatcherService({
            watchDir: options.dir,
          });
          const initStart = Date.now();
          await this.service.initialize();
          console.log(chalk.gray(`   Done in ${Date.now() - initStart}ms`));

          // Step 2: Prevention check
          console.log(
            chalk.blue("\n2.") + chalk.bold(" Running prevention checks...")
          );
          const prevStart = Date.now();
          const preventionResult = await this.service
            .getPreventionModule()
            ?.processFile(testFile);
          const prevDuration = Date.now() - prevStart;

          if (preventionResult) {
            if (preventionResult.success) {
              console.log(
                "   " +
                  chalk.green("Ô£ö") +
                  " Passed" +
                  chalk.gray(` (${prevDuration}ms)`)
              );
            } else {
              console.log(
                "   " +
                  chalk.red("Ô£û") +
                  " Failed" +
                  chalk.gray(` (${prevDuration}ms)`)
              );
              if (preventionResult.errors?.length > 0) {
                for (const err of preventionResult.errors) {
                  console.log("     " + chalk.red("ÔÇó") + " " + err);
                }
              }
            }
            if (preventionResult.warnings?.length > 0) {
              for (const warn of preventionResult.warnings) {
                console.log("     " + chalk.yellow("ÔÇó") + " " + warn);
              }
            }
          } else {
            console.log(
              "   " + chalk.yellow("ÔÜá Skipped (module not available)")
            );
          }

          // Step 3: Trigger processing
          console.log(
            chalk.blue("\n3.") + chalk.bold(" Running trigger processing...")
          );
          const trigStart = Date.now();
          const triggerResult = await this.service
            .getTriggerModule()
            ?.processEvent({
              filePath: testFile,
              eventType: "fileDetected",
              metadata: { preventionResult },
              timestamp: new Date(),
            });
          const trigDuration = Date.now() - trigStart;

          if (triggerResult && triggerResult.length > 0) {
            const firstResult = triggerResult[0];
            if (firstResult.success) {
              console.log(
                "   " +
                  chalk.green("Ô£ö") +
                  " Completed" +
                  chalk.gray(` (${trigDuration}ms)`)
              );
            } else {
              console.log(
                "   " +
                  chalk.red("Ô£û") +
                  " Failed" +
                  chalk.gray(` (${trigDuration}ms)`)
              );
            }
            for (const result of triggerResult) {
              for (const action of result.actions) {
                const icon = action.success ? chalk.green("Ô£ö") : chalk.red("Ô£û");
                console.log("     " + icon + " " + action.type);
              }
            }
          } else {
            console.log(
              "   " + chalk.yellow("ÔÜá Skipped (module not available)")
            );
          }

          // Summary
          console.log(chalk.bold("\nSummary\n"));
          console.log(
            "  " +
              chalk.gray("Total time: ") +
              chalk.cyan(`${Date.now() - prevStart}ms`)
          );
          console.log("  " + chalk.gray("File: ") + chalk.cyan(testFile));
          console.log();

          // Cleanup
          if (cleanupNeeded) {
            await fs.remove(path.dirname(testFile));
          }
        } catch (error) {
          console.error(chalk.red("Ô£û") + " Error in pipeline test:", error);
          process.exit(1);
        }
      });
  }

  private printMetrics(): void {
    const metrics = this.service.getMetrics();
    if (metrics.filesProcessed > 0) {
      console.log(chalk.bold("\nSession Metrics\n"));
      console.log(
        "  " +
          chalk.gray("Files processed:") +
          " " +
          chalk.cyan(String(metrics.filesProcessed))
      );
      console.log(
        "  " +
          chalk.gray("Files corrected:") +
          " " +
          chalk.green(String(metrics.filesCorrected))
      );
      console.log(
        "  " +
          chalk.gray("Files failed:") +
          " " +
          chalk.red(String(metrics.filesFailed))
      );
      if (metrics.totalProcessingTime > 0) {
        const avg = Math.round(
          metrics.totalProcessingTime / metrics.filesProcessed
        );
        console.log(
          "  " +
            chalk.gray("Avg processing time:") +
            " " +
            chalk.cyan(`${avg}ms`)
        );
      }
      console.log();
    }
  }

  /**
   * Preview/dry-run command ÔÇö show what corrections would be applied without writing
   */
  private setupPreviewCommand(): void {
    this.program
      .command("preview")
      .description("Preview corrections without writing changes (dry-run)")
      .argument("<files...>", "Files to preview corrections for")
      .action(async (files: string[]) => {
        try {
          const registry = createCorrectorRegistry();
          let totalCorrections = 0;
          let totalErrors = 0;

          for (const filePath of files) {
            const resolved = path.resolve(filePath);
            if (!(await fs.pathExists(resolved))) {
              console.log(
                chalk.red("Ô£û") + " File not found: " + chalk.bold(resolved)
              );
              totalErrors++;
              continue;
            }

            const results = await registry.applyCorrections(
              resolved,
              undefined,
              true
            );
            const corrected = results.filter((r) => r.corrected);

            if (corrected.length === 0) {
              console.log(
                chalk.green("Ô£ö") + " " + chalk.gray(resolved) + " ÔÇö no changes"
              );
              continue;
            }

            console.log(chalk.bold("\n" + resolved));
            for (const result of corrected) {
              if (result.originalContent && result.correctedContent) {
                const oldLines = result.originalContent.split("\n");
                const newLines = result.correctedContent.split("\n");
                const maxLen = Math.max(oldLines.length, newLines.length);
                for (let i = 0; i < maxLen; i++) {
                  const oldLine = oldLines[i];
                  const newLine = newLines[i];
                  if (oldLine !== newLine) {
                    if (oldLine !== undefined) {
                      console.log(chalk.red(`  - ${i + 1}: ${oldLine}`));
                    }
                    if (newLine !== undefined) {
                      console.log(chalk.green(`  + ${i + 1}: ${newLine}`));
                    }
                  }
                }
              }
              totalCorrections++;
            }
          }

          console.log(
            chalk.bold(
              `\n${totalCorrections} correction(s) would be applied to ${
                files.length - totalErrors
              } file(s)`
            )
          );
        } catch (error) {
          console.error(
            chalk.red("Ô£û") +
              " Preview failed: " +
              (error instanceof Error ? error.message : String(error))
          );
          process.exit(1);
        }
      });
  }

  /**
   * Parse and execute CLI commands
   */
  async run(): Promise<void> {
    try {
      await this.program.parseAsync(process.argv);
    } catch (error) {
      logger.error("CLI error:", error);
      process.exit(1);
    }
  }
}

import EventEmitter from "events";
import { FileEvent } from "./filters.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("detection-events");

/**
 * Custom event types for the detection module
 */
export enum DetectionEvent {
  // File system events
  FILE_DETECTED = "fileDetected",
  FILE_MODIFIED = "fileModified",
  FILE_DELETED = "fileDeleted",

  // Processing events
  PROCESSING_STARTED = "processingStarted",
  PROCESSING_COMPLETED = "processingCompleted",
  PROCESSING_FAILED = "processingFailed",

  // Batch events
  BATCH_STARTED = "batchStarted",
  BATCH_COMPLETED = "batchCompleted",

  // Error events
  DETECTION_ERROR = "detectionError",
  VALIDATION_ERROR = "validationError",
}

/**
 * Event data structures
 */
export interface FileDetectedEvent {
  file: FileEvent;
  source: "watcher" | "scan";
}

export interface ProcessingEvent {
  file: FileEvent;
  processor: string;
  startTime: Date;
  endTime?: Date;
  duration?: number;
  success?: boolean;
  error?: Error;
  metadata?: Record<string, any>;
}

export interface BatchEvent {
  files: FileEvent[];
  totalCount: number;
  processedCount: number;
  failedCount: number;
  startTime: Date;
  endTime?: Date;
  duration?: number;
}

export interface DetectionErrorEvent {
  error: Error;
  context: string;
  file?: FileEvent;
  timestamp: Date;
}

/**
 * Event bus for the detection module
 * Extends EventEmitter to provide typed events and better error handling
 */
export class DetectionEventBus extends EventEmitter {
  constructor() {
    super();
    this.setMaxListeners(50); // Increase default limit for multiple listeners
  }

  /**
   * Emit file detected event
   */
  emitFileDetected(
    file: FileEvent,
    source: "watcher" | "scan" = "watcher"
  ): void {
    const event: FileDetectedEvent = { file, source };
    logger.debug(`Emitting FILE_DETECTED: ${file.filePath}`);
    this.emit(DetectionEvent.FILE_DETECTED, event);
  }

  /**
   * Emit file modified event
   */
  emitFileModified(file: FileEvent): void {
    logger.debug(`Emitting FILE_MODIFIED: ${file.filePath}`);
    this.emit(DetectionEvent.FILE_MODIFIED, { file });
  }

  /**
   * Emit file deleted event
   */
  emitFileDeleted(file: FileEvent): void {
    logger.debug(`Emitting FILE_DELETED: ${file.filePath}`);
    this.emit(DetectionEvent.FILE_DELETED, { file });
  }

  /**
   * Emit processing started event
   */
  emitProcessingStarted(file: FileEvent, processor: string): void {
    const event: ProcessingEvent = {
      file,
      processor,
      startTime: new Date(),
    };
    logger.debug(
      `Emitting PROCESSING_STARTED: ${file.filePath} by ${processor}`
    );
    this.emit(DetectionEvent.PROCESSING_STARTED, event);
  }

  /**
   * Emit processing completed event
   */
  emitProcessingCompleted(
    file: FileEvent,
    processor: string,
    metadata?: Record<string, any>
  ): void {
    const endTime = new Date();
    const duration = endTime.getTime() - file.timestamp.getTime();

    const event: ProcessingEvent = {
      file,
      processor,
      startTime: file.timestamp,
      endTime,
      duration,
      success: true,
      metadata,
    };

    logger.debug(
      `Emitting PROCESSING_COMPLETED: ${file.filePath} by ${processor} (${duration}ms)`
    );
    this.emit(DetectionEvent.PROCESSING_COMPLETED, event);
  }

  /**
   * Emit processing failed event
   */
  emitProcessingFailed(
    file: FileEvent,
    processor: string,
    error: Error,
    metadata?: Record<string, any>
  ): void {
    const endTime = new Date();
    const duration = endTime.getTime() - file.timestamp.getTime();

    const event: ProcessingEvent = {
      file,
      processor,
      startTime: file.timestamp,
      endTime,
      duration,
      success: false,
      error,
      metadata,
    };

    logger.warn(
      `Emitting PROCESSING_FAILED: ${file.filePath} by ${processor}: ${error.message}`
    );
    this.emit(DetectionEvent.PROCESSING_FAILED, event);
  }

  /**
   * Emit batch started event
   */
  emitBatchStarted(files: FileEvent[]): void {
    const event: BatchEvent = {
      files,
      totalCount: files.length,
      processedCount: 0,
      failedCount: 0,
      startTime: new Date(),
    };

    logger.info(`Emitting BATCH_STARTED: ${files.length} files`);
    this.emit(DetectionEvent.BATCH_STARTED, event);
  }

  /**
   * Emit batch completed event
   */
  emitBatchCompleted(
    totalCount: number,
    processedCount: number,
    failedCount: number,
    duration: number
  ): void {
    const event: BatchEvent = {
      files: [],
      totalCount,
      processedCount,
      failedCount,
      startTime: new Date(Date.now() - duration),
      endTime: new Date(),
      duration,
    };

    logger.info(
      `Emitting BATCH_COMPLETED: ${processedCount}/${totalCount} processed, ${failedCount} failed (${duration}ms)`
    );
    this.emit(DetectionEvent.BATCH_COMPLETED, event);
  }

  /**
   * Emit detection error event
   */
  emitDetectionError(error: Error, context: string, file?: FileEvent): void {
    const event: DetectionErrorEvent = {
      error,
      context,
      file,
      timestamp: new Date(),
    };

    logger.error(`Emitting DETECTION_ERROR in ${context}: ${error.message}`);
    this.emit(DetectionEvent.DETECTION_ERROR, event);
  }

  /**
   * Emit validation error event
   */
  emitValidationError(error: Error, file?: FileEvent): void {
    const event: DetectionErrorEvent = {
      error,
      context: "validation",
      file,
      timestamp: new Date(),
    };

    logger.warn(`Emitting VALIDATION_ERROR: ${error.message}`);
    this.emit(DetectionEvent.VALIDATION_ERROR, event);
  }
}

/**
 * Global event bus instance
 */
export const eventBus = new DetectionEventBus();

/**
 * Utility functions for event handling
 */
export class EventUtils {
  /**
   * Create a typed event listener
   */
  static createListener<T>(
    event: DetectionEvent,
    handler: (data: T) => void | Promise<void>
  ): (data: T) => void | Promise<void> {
    return handler;
  }

  /**
   * Wrap async event handler with error handling
   */
  static wrapAsyncHandler<T>(
    handler: (data: T) => Promise<void>
  ): (data: T) => Promise<void> {
    return async (data: T) => {
      try {
        await handler(data);
      } catch (error) {
        logger.error("Error in async event handler:", error);
        // Re-emit as detection error if possible
        if (eventBus.listenerCount(DetectionEvent.DETECTION_ERROR) > 0) {
          eventBus.emitDetectionError(
            error instanceof Error ? error : new Error(String(error)),
            "event_handler"
          );
        }
      }
    };
  }

  /**
   * Create a debounced event handler
   */
  static debounce<T>(
    handler: (data: T) => void,
    delay: number
  ): (data: T) => void {
    let timeoutId: NodeJS.Timeout | null = null;

    return (data: T) => {
      if (timeoutId) {
        clearTimeout(timeoutId);
      }

      timeoutId = setTimeout(() => {
        handler(data);
        timeoutId = null;
      }, delay);
    };
  }
}

/**
 * Event handler decorators for cleaner code
 */
export function OnEvent(event: DetectionEvent) {
  return function (
    target: any,
    propertyKey: string,
    descriptor: PropertyDescriptor
  ) {
    const method = descriptor.value;

    // Register the method as an event listener
    process.nextTick(() => {
      eventBus.on(event, method.bind(target));
    });

    return descriptor;
  };
}

