import fs from "fs-extra";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("detection-filters");

/**
 * File event data structure
 */
export interface FileEvent {
  filePath: string;
  relativePath: string;
  extension: string;
  timestamp: Date;
}

/**
 * Filter criteria for file events
 */
export interface FilterCriteria {
  extensions?: string[];
  excludePatterns?: string[];
  includePatterns?: string[];
  maxFileSize?: number;
  minFileSize?: number;
  modifiedWithin?: number; // milliseconds
}

/**
 * Filter result
 */
export interface FilterResult {
  passed: boolean;
  reason?: string;
  metadata?: Record<string, any>;
}

/**
 * File filter class for applying various filtering rules to file events
 */
export class FileFilter {
  private criteria: FilterCriteria;

  constructor(criteria: FilterCriteria = {}) {
    this.criteria = criteria;
  }

  /**
   * Apply all filters to a file event
   */
  async apply(event: FileEvent): Promise<FilterResult> {
    // Extension filter
    if (this.criteria.extensions && this.criteria.extensions.length > 0) {
      const extensionFilter = this.filterByExtension(event);
      if (!extensionFilter.passed) {
        return extensionFilter;
      }
    }

    // Pattern filters
    if (
      this.criteria.excludePatterns &&
      this.criteria.excludePatterns.length > 0
    ) {
      const excludeFilter = this.filterByExcludePatterns(event);
      if (!excludeFilter.passed) {
        return excludeFilter;
      }
    }

    if (
      this.criteria.includePatterns &&
      this.criteria.includePatterns.length > 0
    ) {
      const includeFilter = this.filterByIncludePatterns(event);
      if (!includeFilter.passed) {
        return includeFilter;
      }
    }

    // File size filters
    if (this.criteria.maxFileSize || this.criteria.minFileSize) {
      const sizeFilter = await this.filterByFileSize(event);
      if (!sizeFilter.passed) {
        return sizeFilter;
      }
    }

    // Modification time filter
    if (this.criteria.modifiedWithin) {
      const timeFilter = await this.filterByModificationTime(event);
      if (!timeFilter.passed) {
        return timeFilter;
      }
    }

    return { passed: true, metadata: { filters: "all_passed" } };
  }

  /**
   * Filter by file extension
   */
  private filterByExtension(event: FileEvent): FilterResult {
    if (!this.criteria.extensions?.includes(event.extension)) {
      return {
        passed: false,
        reason: `Extension '${
          event.extension
        }' not in allowed list: ${this.criteria.extensions?.join(", ")}`,
      };
    }
    return { passed: true };
  }

  /**
   * Filter by exclude patterns
   */
  private filterByExcludePatterns(event: FileEvent): FilterResult {
    for (const pattern of this.criteria.excludePatterns!) {
      if (this.matchesPattern(event.relativePath, pattern)) {
        return {
          passed: false,
          reason: `Path matches exclude pattern: ${pattern}`,
        };
      }
    }
    return { passed: true };
  }

  /**
   * Filter by include patterns
   */
  private filterByIncludePatterns(event: FileEvent): FilterResult {
    const matchesAnyPattern = this.criteria.includePatterns!.some((pattern) =>
      this.matchesPattern(event.relativePath, pattern)
    );

    if (!matchesAnyPattern) {
      return {
        passed: false,
        reason: `Path doesn't match any include pattern: ${this.criteria.includePatterns?.join(
          ", "
        )}`,
      };
    }
    return { passed: true };
  }

  /**
   * Filter by file size
   */
  private async filterByFileSize(event: FileEvent): Promise<FilterResult> {
    try {
      const stats = await fs.stat(event.filePath);
      const fileSize = stats.size;

      if (this.criteria.maxFileSize && fileSize > this.criteria.maxFileSize) {
        return {
          passed: false,
          reason: `File size ${fileSize} bytes exceeds maximum ${this.criteria.maxFileSize} bytes`,
          metadata: { fileSize },
        };
      }

      if (this.criteria.minFileSize && fileSize < this.criteria.minFileSize) {
        return {
          passed: false,
          reason: `File size ${fileSize} bytes is below minimum ${this.criteria.minFileSize} bytes`,
          metadata: { fileSize },
        };
      }

      return { passed: true, metadata: { fileSize } };
    } catch (error) {
      logger.warn(`Could not get file size for ${event.filePath}:`, error);
      return {
        passed: false,
        reason: "Could not determine file size",
      };
    }
  }

  /**
   * Filter by modification time
   */
  private async filterByModificationTime(
    event: FileEvent
  ): Promise<FilterResult> {
    try {
      const stats = await fs.stat(event.filePath);
      const now = Date.now();
      const modifiedTime = stats.mtime.getTime();
      const timeDiff = now - modifiedTime;

      if (timeDiff > this.criteria.modifiedWithin!) {
        return {
          passed: false,
          reason: `File was modified ${timeDiff}ms ago, exceeds limit of ${this.criteria.modifiedWithin}ms`,
          metadata: { modifiedTime, timeDiff },
        };
      }

      return { passed: true, metadata: { modifiedTime, timeDiff } };
    } catch (error) {
      logger.warn(
        `Could not get modification time for ${event.filePath}:`,
        error
      );
      return {
        passed: false,
        reason: "Could not determine modification time",
      };
    }
  }

  /**
   * Check if a file path matches a pattern
   */
  private matchesPattern(filePath: string, pattern: string): boolean {
    // Simple pattern matching - can be extended for more complex patterns
    if (pattern.includes("*") || pattern.includes("?")) {
      // Convert glob pattern to regex
      const regexPattern = pattern
        .replace(/\./g, "\\.")
        .replace(/\*/g, ".*")
        .replace(/\?/g, ".");
      return new RegExp(`^${regexPattern}$`).test(filePath);
    }

    // Exact match
    return filePath.includes(pattern);
  }

  /**
   * Update filter criteria
   */
  updateCriteria(newCriteria: Partial<FilterCriteria>): void {
    this.criteria = { ...this.criteria, ...newCriteria };
    logger.info("Filter criteria updated:", this.criteria);
  }

  /**
   * Get current filter criteria
   */
  getCriteria(): FilterCriteria {
    return { ...this.criteria };
  }
}

/**
 * Predefined filter presets
 */
export const FilterPresets = {
  /**
   * Default filter for TypeScript/JavaScript projects
   */
  jsTsProject: (): FilterCriteria => ({
    extensions: ["js", "ts", "jsx", "tsx", "json", "md"],
    excludePatterns: ["node_modules/**", "dist/**", "build/**", ".git/**"],
    maxFileSize: 1024 * 1024, // 1MB
  }),

  /**
   * Minimal filter for quick scanning
   */
  minimal: (): FilterCriteria => ({
    extensions: ["js", "ts"],
    excludePatterns: ["node_modules/**"],
  }),

  /**
   * Comprehensive filter for full project analysis
   */
  comprehensive: (): FilterCriteria => ({
    extensions: [
      "js",
      "ts",
      "jsx",
      "tsx",
      "json",
      "md",
      "css",
      "scss",
      "html",
      "yaml",
      "yml",
    ],
    excludePatterns: [
      "node_modules/**",
      "dist/**",
      "build/**",
      ".git/**",
      "*.log",
    ],
    maxFileSize: 5 * 1024 * 1024, // 5MB
    modifiedWithin: 24 * 60 * 60 * 1000, // Last 24 hours
  }),
};

/**
 * Factory function to create a file filter
 */
export function createFileFilter(criteria?: FilterCriteria): FileFilter {
  return new FileFilter(criteria);
}

export default FileFilter;

import { Watcher, WatcherEvent, createWatcher } from "./watcher.js";
import { FileFilter, FilterPresets, createFileFilter } from "./filters.js";
import {
  DetectionEventBus,
  DetectionEvent,
  eventBus as defaultEventBus,
} from "./events.js";
import { Utils, ConfigSchemas } from "../shared/utils.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("detection");

/**
 * Configuration for the detection module
 */
export interface DetectionConfig {
  watchDir: string;
  excludedDirs: string[];
  watchExtensions: string[];
  processingDelay: number;
  filterPreset?: "jsTsProject" | "minimal" | "comprehensive";
  customFilters?: any;
}

/**
 * Main detection module that orchestrates file watching, filtering, and event emission
 */
export class DetectionModule {
  private watcher: Watcher;
  private filter: FileFilter;
  eventBus: DetectionEventBus;
  private config: DetectionConfig;
  private isRunning: boolean = false;

  constructor(
    config: DetectionConfig,
    dependencies?: { eventBus?: DetectionEventBus }
  ) {
    this.config = config;
    this.eventBus = dependencies?.eventBus || defaultEventBus;

    // Create watcher instance
    this.watcher = createWatcher({
      watchDir: config.watchDir,
      excludedDirs: config.excludedDirs,
      watchExtensions: config.watchExtensions,
      processingDelay: config.processingDelay,
    });

    // Create filter instance (note: extensions also filtered by Watcher.shouldProcessFile -
    // double-check is intentional for defense-in-depth when FileFilter is used standalone)
    const filterCriteria = config.filterPreset
      ? FilterPresets[config.filterPreset]()
      : config.customFilters || {};

    this.filter = createFileFilter(filterCriteria);
  }

  /**
   * Start the detection module
   */
  async start(): Promise<void> {
    if (this.isRunning) {
      logger.warn("Detection module is already running");
      return;
    }

    try {
      logger.info("Starting detection module...");

      // Start the file watcher
      await this.watcher.start();

      // Set up watcher event forwarding
      this.setupWatcherEventForwarding();

      this.isRunning = true;
      logger.info("Detection module started successfully");
    } catch (error) {
      logger.error("Failed to start detection module:", error);
      throw error;
    }
  }

  /**
   * Stop the detection module
   */
  async stop(): Promise<void> {
    if (!this.isRunning) {
      logger.warn("Detection module is not running");
      return;
    }

    try {
      logger.info("Stopping detection module...");

      // Stop the file watcher
      await this.watcher.stop();

      this.isRunning = false;
      logger.info("Detection module stopped successfully");
    } catch (error) {
      logger.error("Failed to stop detection module:", error);
      throw error;
    }
  }

  /**
   * Update filter criteria
   */
  updateFilter(criteria: any): void {
    this.filter.updateCriteria(criteria);
    logger.info("Filter criteria updated");
  }

  /**
   * Get current status
   */
  getStatus(): {
    isRunning: boolean;
    watcherStatus: any;
    filterCriteria: any;
  } {
    return {
      isRunning: this.isRunning,
      watcherStatus: this.watcher.getStatus(),
      filterCriteria: this.filter.getCriteria(),
    };
  }

  /**
   * Reload configuration
   */
  async reloadConfig(): Promise<void> {
    logger.info("Reloading detection configuration...");

    // Re-read configuration from environment variables
    const newConfig: DetectionConfig = {
      watchDir: process.env.WATCH_DIR || this.config.watchDir,
      excludedDirs: (
        process.env.EXCLUDED_DIRS || this.config.excludedDirs.join(",")
      ).split(","),
      watchExtensions: (
        process.env.WATCH_EXTENSIONS || this.config.watchExtensions.join(",")
      ).split(","),
      processingDelay: parseInt(
        process.env.PROCESSING_DELAY || String(this.config.processingDelay)
      ),
      filterPreset: this.config.filterPreset,
      customFilters: this.config.customFilters,
    };

    this.config = newConfig;

    // Recreate the filter with updated criteria
    const filterCriteria = newConfig.filterPreset
      ? FilterPresets[newConfig.filterPreset]()
      : newConfig.customFilters || {};
    this.filter = createFileFilter(filterCriteria);

    // If running, restart the watcher with new config
    if (this.isRunning) {
      await this.watcher.stop();
      this.watcher = createWatcher({
        watchDir: newConfig.watchDir,
        excludedDirs: newConfig.excludedDirs,
        watchExtensions: newConfig.watchExtensions,
        processingDelay: newConfig.processingDelay,
      });
      await this.watcher.start();
      this.setupWatcherEventForwarding();
    }

    logger.info("Detection configuration reloaded");
  }

  /**
   * Set up forwarding of watcher events to detection events
   */
  private setupWatcherEventForwarding(): void {
    // Forward file events through the detection filter
    const forwardEvent = (detectionEvent: DetectionEvent) => {
      return async (event: any) => {
        const filterResult = await this.filter.apply(event);

        if (filterResult.passed) {
          logger.debug(`File passed filter: ${event.filePath}`);
          this.eventBus.emit(detectionEvent, { file: event, filterResult });
        } else {
          logger.debug(
            `File filtered out: ${event.filePath} - ${filterResult.reason}`
          );
        }
      };
    };

    // Set up event forwarding
    this.watcher.on(
      WatcherEvent.FILE_ADDED,
      forwardEvent(DetectionEvent.FILE_DETECTED)
    );
    this.watcher.on(
      WatcherEvent.FILE_CHANGED,
      forwardEvent(DetectionEvent.FILE_MODIFIED)
    );
    this.watcher.on(
      WatcherEvent.FILE_DELETED,
      forwardEvent(DetectionEvent.FILE_DELETED)
    );

    this.watcher.on(WatcherEvent.WATCHER_READY, () => {
      logger.info("File watcher is ready");
    });

    this.watcher.on(WatcherEvent.WATCHER_ERROR, (error) => {
      logger.error("Watcher error:", error);
      this.eventBus.emitDetectionError(error, "watcher");
    });
  }
}

/**
 * Factory function to create a detection module
 */
export function createDetectionModule(
  config?: Partial<DetectionConfig>,
  dependencies?: { eventBus?: DetectionEventBus }
): DetectionModule {
  const defaultConfig: DetectionConfig = {
    watchDir: process.env.WATCH_DIR || process.cwd(),
    excludedDirs: (
      process.env.EXCLUDED_DIRS || "node_modules,.git,dist,build"
    ).split(","),
    watchExtensions: (
      process.env.WATCH_EXTENSIONS || "js,ts,jsx,tsx,json,md"
    ).split(","),
    processingDelay: parseInt(process.env.PROCESSING_DELAY || "100"),
    filterPreset: "jsTsProject",
  };

  const finalConfig = { ...defaultConfig, ...config };

  // Validate configuration
  Utils.validateConfig(finalConfig, ConfigSchemas.watcherConfig);

  return new DetectionModule(finalConfig, dependencies);
}

/**
 * Quick setup function for common use cases
 */
export async function setupDetection(
  config?: Partial<DetectionConfig>
): Promise<DetectionModule> {
  const module = createDetectionModule(config);

  // Note: Signal handlers (SIGINT/SIGTERM) are managed centrally
  // by WatcherService in src/index.ts

  return module;
}

export default DetectionModule;

