    };
  }

  /**
   * Get current configuration
   */
  getConfig(): PreventionConfig {
    return { ...this.config };
  }

  /**
   * Update configuration
   */
  async updateConfig(newConfig: Partial<PreventionConfig>): Promise<void> {
    try {
      const updatedConfig = Utils.validateConfig(
        { ...this.config, ...newConfig },
        this.configSchema
      );

      this.config = updatedConfig;

      // Save to file
      await Utils.writeJsonFile(this.configPath, this.config);
      logger.info("Configuration updated and saved");
    } catch (error) {
      logger.error("Error updating configuration:", error);
      throw error;
    }
  }

  /**
   * Get enabled rules
   */
  getEnabledRules(): PreventionRule[] {
    return this.config.rules.filter(
      (rule) => rule.enabled && this.config.enabled
    );
  }

  /**
   * Get rules applicable to a file
   */
  async getRulesForFile(filePath: string): Promise<PreventionRule[]> {
    const extension = Utils.getFileExtension(filePath);
    const enabledRules = this.getEnabledRules();

    const applicableRules: PreventionRule[] = [];

    for (const rule of enabledRules) {
      if (rule.conditions?.fileExtensions) {
        if (!rule.conditions.fileExtensions.includes(extension)) {
          continue;
        }
      }

      if (rule.conditions?.filePatterns) {
        const matchesPattern = rule.conditions.filePatterns.some((pattern) =>
          filePath.includes(pattern)
        );
        if (!matchesPattern) {
          continue;
        }
      }

      if (rule.conditions?.minFileSize || rule.conditions?.maxFileSize) {
        try {
          const stats = await fs.stat(filePath);
          const fileSize = stats.size;

          if (
            rule.conditions.minFileSize &&
            fileSize < rule.conditions.minFileSize
          ) {
            continue;
          }

          if (
            rule.conditions.maxFileSize &&
            fileSize > rule.conditions.maxFileSize
          ) {
            continue;
          }
        } catch (error) {
          logger.warn(`Could not check file size for ${filePath}:`, error);
          continue;
        }
      }

      applicableRules.push(rule);
    }

    return applicableRules;
  }

  /**
   * Add a new rule
   */
  async addRule(rule: PreventionRule): Promise<void> {
    // Validate the new rule
    const ruleSchema = Joi.object({
      id: Joi.string().required(),
      name: Joi.string().required(),
      description: Joi.string().required(),
      enabled: Joi.boolean().default(true),
      severity: Joi.string()
        .valid("error", "warning", "info")
        .default("warning"),
      category: Joi.string()
        .valid("syntax", "style", "security", "performance", "custom")
        .default("custom"),
      validators: Joi.array().items(Joi.string()).default([]),
      scripts: Joi.array().items(Joi.string()).default([]),
      conditions: Joi.object({
        fileExtensions: Joi.array().items(Joi.string()),
        filePatterns: Joi.array().items(Joi.string()),
        minFileSize: Joi.number(),
        maxFileSize: Joi.number(),
      }).optional(),
      actions: Joi.object({
        autoFix: Joi.boolean().default(false),
        notifyOnFailure: Joi.boolean().default(true),
        blockCommit: Joi.boolean().default(false),
      }).optional(),
    });
    Utils.validateConfig(rule, ruleSchema);

    // Check if rule already exists
    const existingIndex = this.config.rules.findIndex((r) => r.id === rule.id);
    if (existingIndex >= 0) {
      this.config.rules[existingIndex] = rule;
    } else {
      this.config.rules.push(rule);
    }

    await this.saveConfig();
    logger.info(`Rule added/updated: ${rule.id}`);
  }

  /**
   * Remove a rule
   */
  async removeRule(ruleId: string): Promise<boolean> {
    const initialLength = this.config.rules.length;
    this.config.rules = this.config.rules.filter((rule) => rule.id !== ruleId);

    if (this.config.rules.length < initialLength) {
      await this.saveConfig();
      logger.info(`Rule removed: ${ruleId}`);
      return true;
    }

    return false;
  }

  /**
   * Enable/disable a rule
   */
  async toggleRule(ruleId: string, enabled: boolean): Promise<boolean> {
    const rule = this.config.rules.find((r) => r.id === ruleId);
    if (rule) {
      rule.enabled = enabled;
      await this.saveConfig();
      logger.info(`Rule ${ruleId} ${enabled ? "enabled" : "disabled"}`);
      return true;
    }
    return false;
  }

  /**
   * Get configuration statistics
   */
  getStats(): {
    totalRules: number;
    enabledRules: number;
    rulesByCategory: Record<string, number>;
    rulesBySeverity: Record<string, number>;
  } {
    const enabledRules = this.getEnabledRules();
    const rulesByCategory: Record<string, number> = {};
    const rulesBySeverity: Record<string, number> = {};

    this.config.rules.forEach((rule) => {
      rulesByCategory[rule.category] =
        (rulesByCategory[rule.category] || 0) + 1;

      if (rule.enabled) {
        rulesBySeverity[rule.severity] =
          (rulesBySeverity[rule.severity] || 0) + 1;
      }
    });

    return {
      totalRules: this.config.rules.length,
      enabledRules: enabledRules.length,
      rulesByCategory,
      rulesBySeverity,
    };
  }

  /**
   * Save configuration to file
   */
  private async saveConfig(): Promise<void> {
    try {
      await Utils.writeJsonFile(this.configPath, this.config);
    } catch (error) {
      logger.error("Error saving configuration:", error);
      throw error;
    }
  }

  /**
   * Reload configuration from file
   */
  async reloadConfig(): Promise<void> {
    this.config = await this.loadDefaultConfig();
    logger.info("Configuration reloaded");
  }

  /**
   * Export configuration for backup
   */
  exportConfig(): PreventionConfig {
    return JSON.parse(JSON.stringify(this.config));
  }

  /**
   * Import configuration from backup
   */
  async importConfig(config: PreventionConfig): Promise<void> {
    // Validate the imported config
    const { error } = this.configSchema.validate(config);
    if (error) {
      throw new Error(`Invalid configuration: ${error.message}`);
    }

    this.config = config;
    await this.saveConfig();
    logger.info("Configuration imported successfully");
  }
}

/**
 * Create a prevention configuration manager (async factory)
 */
export async function createPreventionConfig(
  configPath?: string
): Promise<PreventionConfigManager> {
  return PreventionConfigManager.create(configPath);
}

export default PreventionConfigManager;

import {
  ValidatorRegistry,
  PatternValidator,
  createValidatorRegistry,
} from "./validators.js";
import { ScriptRunner, createScriptRunner } from "./scripts.js";
import { PreventionConfigManager, createPreventionConfig } from "./config.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("prevention");

/**
 * Prevention result for a file
 */
export interface PreventionResult {
  filePath: string;
  success: boolean;
  errors: Array<{
    rule: string;
    message: string;
    severity: "error" | "warning" | "info";
  }>;
  warnings: Array<{
    rule: string;
    message: string;
    severity: "error" | "warning" | "info";
  }>;
  executionTime: number;
  metadata?: Record<string, any>;
}

/**
 * Prevention module configuration
 */
export interface PreventionModuleConfig {
  configPath?: string;
  enabled?: boolean;
  failOnError?: boolean;
  failOnWarning?: boolean;
  maxExecutionTime?: number;
  parallelExecution?: boolean;
}

/**
 * Main prevention module that orchestrates validation and script execution
 */
export class PreventionModule {
  private configManager!: PreventionConfigManager;
  private validatorRegistry: ValidatorRegistry;
  private scriptRunner: ScriptRunner;
  private config: PreventionModuleConfig;
  private isRunning: boolean = false;

  private constructor(
    config: PreventionModuleConfig,
    dependencies?: {
      validatorRegistry?: ValidatorRegistry;
      scriptRunner?: ScriptRunner;
      configManager?: PreventionConfigManager;
    }
  ) {
    this.config = {
      enabled: true,
      failOnError: true,
      failOnWarning: false,
      maxExecutionTime: 30000,
      parallelExecution: true,
      ...config,
    };

    this.validatorRegistry =
      dependencies?.validatorRegistry || createValidatorRegistry();
    this.scriptRunner = dependencies?.scriptRunner || createScriptRunner();
  }

  /**
   * Create and initialize a PreventionModule (async factory)
   */
  static async create(
    config: PreventionModuleConfig = {},
    dependencies?: {
      validatorRegistry?: ValidatorRegistry;
      scriptRunner?: ScriptRunner;
      configManager?: PreventionConfigManager;
    }
  ): Promise<PreventionModule> {
    const module = new PreventionModule(config, dependencies);
    module.configManager =
      dependencies?.configManager ||
      (await createPreventionConfig(config.configPath));
    return module;
  }

  /**
   * Start the prevention module
   */
  async start(): Promise<void> {
    if (this.isRunning) {
      logger.warn("Prevention module is already running");
      return;
    }

    try {
      logger.info("Starting prevention module...");

      // Update component configurations
      await this.updateComponentConfigurations();

      this.isRunning = true;
      logger.info("Prevention module started successfully");
    } catch (error) {
      logger.error("Failed to start prevention module:", error);
      throw error;
    }
  }

  /**
   * Stop the prevention module
   */
  async stop(): Promise<void> {
    if (!this.isRunning) {
      logger.warn("Prevention module is not running");
      return;
    }

    try {
      logger.info("Stopping prevention module...");

      // Stop all running scripts
      this.scriptRunner.stopAllScripts();

      this.isRunning = false;
      logger.info("Prevention module stopped successfully");
    } catch (error) {
      logger.error("Failed to stop prevention module:", error);
      throw error;
    }
  }

  /**
   * Process a file through all applicable prevention rules
   */
  async processFile(filePath: string): Promise<PreventionResult> {
    if (!this.isRunning || !this.config.enabled) {
      return {
        filePath,
        success: true,
        errors: [],
        warnings: [],
        executionTime: 0,
      };
    }

    const startTime = Date.now();
    const result: PreventionResult = {
      filePath,
      success: true,
      errors: [],
      warnings: [],
      executionTime: 0,
    };

    try {
      logger.info(`Processing file: ${filePath}`);

      // Get applicable rules for this file
      const applicableRules = await this.configManager.getRulesForFile(
        filePath
      );

      if (applicableRules.length === 0) {
        logger.debug(`No prevention rules applicable for file: ${filePath}`);
        result.executionTime = Date.now() - startTime;
        return result;
      }

      logger.info(
        `Applying ${applicableRules.length} prevention rules to ${filePath}`
      );

      // Process each rule
      for (const rule of applicableRules) {
        try {
          const ruleResult = await this.processRule(filePath, rule);
          result.errors.push(...ruleResult.errors);
          result.warnings.push(...ruleResult.warnings);

          if (ruleResult.errors.length > 0 && this.config.failOnError) {
            result.success = false;
          }

          if (ruleResult.warnings.length > 0 && this.config.failOnWarning) {
            result.success = false;
          }
        } catch (err) {
          const error = err instanceof Error ? err : new Error(String(err));
          logger.error(
            `Error processing rule ${rule.id} for ${filePath}:`,
            error
          );
          result.errors.push({
            rule: rule.id,
            message: `Rule processing failed: ${error.message}`,
            severity: "error",
          });
          result.success = false;
        }
      }

      // Execute applicable scripts
      try {
        const scriptResults = await this.scriptRunner.executeScriptsForFile(
          filePath
        );
        for (const scriptResult of scriptResults) {
          if (!scriptResult.success) {
            result.errors.push({
              rule: scriptResult.error?.message || "script-failed",
              message: `Script execution failed: ${scriptResult.stderr}`,
              severity: "error",
            });
            result.success = false;
          }
        }
      } catch (err) {
        const error = err instanceof Error ? err : new Error(String(err));
        logger.error(`Error executing scripts for ${filePath}:`, error);
        result.errors.push({
          rule: "script-execution",
          message: `Script execution error: ${error.message}`,
          severity: "error",
        });
        result.success = false;
      }

      result.executionTime = Date.now() - startTime;

      logger.info(
        `Prevention processing completed for ${filePath}: ${
          result.success ? "SUCCESS" : "FAILED"
        } ` +
          `(${result.errors.length} errors, ${result.warnings.length} warnings) in ${result.executionTime}ms`
      );
    } catch (err) {
      const error = err instanceof Error ? err : new Error(String(err));
      logger.error(`Error in prevention processing for ${filePath}:`, error);
      result.success = false;
      result.errors.push({
        rule: "prevention-error",
        message: `Prevention processing failed: ${error.message}`,
        severity: "error",
      });
      result.executionTime = Date.now() - startTime;
    }

    return result;
  }

  /**
   * Process a single rule for a file
   */
  private async processRule(
    filePath: string,
    rule: any
  ): Promise<{
    errors: Array<{
      rule: string;
      message: string;
      severity: "error" | "warning" | "info";
    }>;
    warnings: Array<{
      rule: string;
      message: string;
      severity: "error" | "warning" | "info";
    }>;
  }> {
    const errors: Array<{
      rule: string;
      message: string;
      severity: "error" | "warning" | "info";
    }> = [];
    const warnings: Array<{
      rule: string;
      message: string;
      severity: "error" | "warning" | "info";
    }> = [];

    // Run validators
    for (const validatorName of rule.validators) {
      const validator = this.validatorRegistry.get(validatorName);
      if (validator && validator.isEnabled()) {
        try {
          const validationResult = await validator.validate(filePath);

          for (const err of validationResult.errors) {
            errors.push({
              rule: `${rule.id}:${err.rule}`,
              message: err.message,
              severity: err.severity || "error",
            });
          }

          for (const warning of validationResult.warnings) {
            warnings.push({
              rule: `${rule.id}:${warning.rule}`,
              message: warning.message,
              severity: warning.severity || "warning",
            });
          }
        } catch (err) {
          const error = err instanceof Error ? err : new Error(String(err));
          logger.error(
            `Validator ${validatorName} failed for rule ${rule.id}:`,
            error
          );
          errors.push({
            rule: `${rule.id}:${validatorName}`,
            message: `Validator failed: ${error.message}`,
            severity: "error",
          });
        }
      }
    }

    return { errors, warnings };
  }

  /**
   * Update component configurations based on current settings
   */
  private async updateComponentConfigurations(): Promise<void> {
    const config = this.configManager.getConfig();

    // Update script runner with custom scripts
    if (config.customScripts) {
      for (const customScript of config.customScripts) {
        this.scriptRunner.addScript(customScript.config);
      }
    }

    // Update validator registry with custom validators
    if (config.customValidators) {
      for (const customValidator of config.customValidators) {
        const validator = new PatternValidator({
          enabled: true,
          rules: {},
          customRules: customValidator.config?.customRules || [],
        });
        this.validatorRegistry.register(customValidator.name, validator);
        logger.info(`Custom validator registered: ${customValidator.name}`);
      }
    }
  }

  /**
   * Get current status
   */
  getStatus(): {
    isRunning: boolean;
    enabled: boolean;
    ruleCount: number;
    enabledRuleCount: number;
    validatorCount: number;
    scriptCount: number;
    configStats: any;
  } {
    const configStats = this.configManager.getStats();

    return {
      isRunning: this.isRunning,
      enabled: this.config.enabled ?? true,
      ruleCount: configStats.totalRules,
      enabledRuleCount: configStats.enabledRules,
      validatorCount: this.validatorRegistry.getAll().length,
      scriptCount: this.scriptRunner.getScripts().length,
      configStats,
    };
  }

  /**
   * Reload configuration
   */
  async reloadConfig(): Promise<void> {
    await this.configManager.reloadConfig();
    await this.updateComponentConfigurations();
    logger.info("Configuration reloaded");
  }

  /**
   * Add a custom rule
   */
  async addRule(rule: any): Promise<void> {
    await this.configManager.addRule(rule);
    await this.updateComponentConfigurations();
  }

  /**
   * Remove a rule
   */
  async removeRule(ruleId: string): Promise<boolean> {
    const removed = await this.configManager.removeRule(ruleId);
    if (removed) {
      await this.updateComponentConfigurations();
    }
    return removed;
  }

  /**
   * Toggle a rule
   */
  async toggleRule(ruleId: string, enabled: boolean): Promise<boolean> {
    const toggled = await this.configManager.toggleRule(ruleId, enabled);
    if (toggled) {
      await this.updateComponentConfigurations();
    }
    return toggled;
  }
}

/**
 * Factory function to create a prevention module (async)
 */
export async function createPreventionModule(
  config?: PreventionModuleConfig,
  dependencies?: {
    validatorRegistry?: ValidatorRegistry;
    scriptRunner?: ScriptRunner;
    configManager?: PreventionConfigManager;
  }
): Promise<PreventionModule> {
  return PreventionModule.create(config, dependencies);
}

/**
 * Quick setup function for common use cases
 */
export async function setupPrevention(
  config?: PreventionModuleConfig
): Promise<PreventionModule> {
  const module = await createPreventionModule(config);
  await module.start();
  return module;
}

export default PreventionModule;

import fs from "fs-extra";
import { Utils, safeSpawn } from "../shared/utils.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("prevention-validators");

/**
 * Validation result interface
 */
export interface ValidationResult {
  isValid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  metadata?: Record<string, any>;
}

/**
 * Validation error interface
 */
export interface ValidationError {
  rule: string;
  message: string;
  file: string;
  line?: number;
  column?: number;
  severity: "error" | "warning";
  code?: string;
}

/**
 * Validation warning interface
 */
export interface ValidationWarning {
  rule: string;
  message: string;
  file: string;
  line?: number;
  column?: number;
  severity?: "error" | "warning";
  suggestion?: string;
}

/**
 * Validator configuration
 */
export interface ValidatorConfig {
  enabled: boolean;
  rules: Record<string, any>;
  customRules?: Array<{
    name: string;
    pattern: RegExp;
    message: string;
    severity: "error" | "warning";
  }>;
}

/**
 * Base validator class
 */
export abstract class BaseValidator {
  protected config: ValidatorConfig;
  protected name: string;

  constructor(name: string, config: ValidatorConfig) {
    this.name = name;
    this.config = config;
  }

  /**
   * Validate a file
   */
  abstract validate(filePath: string): Promise<ValidationResult>;

  /**
   * Get validator name
   */
  getName(): string {
    return this.name;
  }

  /**
   * Check if validator is enabled
   */
  isEnabled(): boolean {
    return this.config.enabled;
  }

  /**
   * Update configuration
   */
  updateConfig(config: Partial<ValidatorConfig>): void {
    this.config = { ...this.config, ...config };
  }
}

/**
 * ESLint validator for JavaScript/TypeScript files
 */
export class ESLintValidator extends BaseValidator {
  constructor(config: ValidatorConfig) {
    super("eslint", config);
  }

  async validate(filePath: string): Promise<ValidationResult> {
    const result: ValidationResult = {
      isValid: true,
      errors: [],
      warnings: [],
    };

    if (!this.isEnabled()) {
      return result;
    }

    try {
      // Check if ESLint is available
      await this.checkESLintAvailability();

      // Run ESLint on the file
      const { stdout, stderr } = await safeSpawn("npx", [
        "eslint",
        filePath,
        "--format=json",
      ]);

      if (stderr) {
        logger.warn(`ESLint stderr for ${filePath}:`, stderr);
      }

      // Parse ESLint output
      const eslintResults = JSON.parse(stdout);

      for (const fileResult of eslintResults) {
        for (const message of fileResult.messages) {
          const validationMessage: ValidationError = {
            rule: message.ruleId || "unknown",
            message: message.message,
            file: filePath,
            line: message.line,
            column: message.column,
            severity: message.severity === 2 ? "error" : "warning",
            code: await this.getCodeSnippet(filePath, message.line),
          };

          if (message.severity === 2) {
            result.errors.push(validationMessage);
            result.isValid = false;
          } else {
            result.warnings.push({
              rule: validationMessage.rule,
              message: validationMessage.message,
              file: validationMessage.file,
              line: validationMessage.line,
              column: validationMessage.column,
              suggestion: message.suggestions?.[0],
            });
          }
        }
      }

      logger.debug(
        `ESLint validation completed for ${filePath}: ${result.errors.length} errors, ${result.warnings.length} warnings`
      );
    } catch (error: any) {
      if (error.code === "ENOENT") {
        logger.warn("ESLint not found, skipping validation");
        result.warnings.push({
          rule: "eslint-not-found",
          message: "ESLint is not installed or not in PATH",
          file: filePath,
          suggestion: "Install ESLint: npm install -g eslint",
        });
      } else {
        logger.error(`ESLint validation failed for ${filePath}:`, error);
        result.errors.push({
          rule: "eslint-error",
          message: `ESLint execution failed: ${error.message}`,
          file: filePath,
          severity: "error",
        });
        result.isValid = false;
      }
    }

    return result;
  }

  private eslintAvailable: boolean | null = null;

  private async checkESLintAvailability(): Promise<void> {
    if (this.eslintAvailable === true) return;

    try {
      await safeSpawn("npx", ["eslint", "--version"]);
      this.eslintAvailable = true;
    } catch (error) {
      this.eslintAvailable = false;
      throw new Error(
        "ESLint is not available. Please install it: npm install -g eslint"
      );
    }
  }

  private async getCodeSnippet(
    filePath: string,
    lineNumber?: number
  ): Promise<string | undefined> {
    if (!lineNumber) return undefined;

    try {
      const content = await fs.readFile(filePath, "utf-8");
      const lines = content.split("\n");

      if (lineNumber <= lines.length) {
        return lines[lineNumber - 1].trim();
      }
    } catch (error) {
      logger.warn(`Could not read code snippet for ${filePath}:${lineNumber}`);
    }

    return undefined;
  }
}

/**
 * JSON validator
 */
export class JSONValidator extends BaseValidator {
  constructor(config: ValidatorConfig) {
    super("json", config);
  }

  async validate(filePath: string): Promise<ValidationResult> {
    const result: ValidationResult = {
      isValid: true,
      errors: [],
      warnings: [],
    };

    if (!this.isEnabled()) {
      return result;
    }

    try {
      const content = await fs.readFile(filePath, "utf-8");

      // Basic JSON syntax validation
      JSON.parse(content);

      logger.debug(`JSON validation passed for ${filePath}`);
    } catch (error: any) {
      result.isValid = false;
      result.errors.push({
        rule: "json-syntax",
        message: `Invalid JSON: ${error.message}`,
        file: filePath,
        severity: "error",
      });
    }

    return result;
  }
}

/**
 * YAML validator (if yaml package is available)
 */
export class YAMLValidator extends BaseValidator {
  constructor(config: ValidatorConfig) {
    super("yaml", config);
  }

  async validate(filePath: string): Promise<ValidationResult> {
    const result: ValidationResult = {
      isValid: true,
      errors: [],
      warnings: [],
    };

    if (!this.isEnabled()) {
      return result;
    }

    try {
      // Check if yaml package is available
      // @ts-expect-error - yaml is optional, handled gracefully at runtime
      const yaml: any = await import("yaml").catch(() => null);

      if (!yaml) {
        logger.debug("YAML package not available, skipping YAML validation");
        return result;
      }

      const content = await fs.readFile(filePath, "utf-8");
      yaml.parse(content);

      logger.debug(`YAML validation passed for ${filePath}`);
    } catch (error: any) {
      if (error.code === "MODULE_NOT_FOUND") {
        logger.debug("YAML package not available, skipping YAML validation");
      } else {
        result.isValid = false;
        result.errors.push({
          rule: "yaml-syntax",
          message: `Invalid YAML: ${error.message}`,
          file: filePath,
          severity: "error",
        });
      }
    }

    return result;
  }
}

/**
 * Custom pattern validator
 */
export class PatternValidator extends BaseValidator {
  constructor(config: ValidatorConfig) {
    super("pattern", config);
  }

  async validate(filePath: string): Promise<ValidationResult> {
    const result: ValidationResult = {
      isValid: true,
      errors: [],
      warnings: [],
    };

    if (!this.isEnabled() || !this.config.customRules) {
      return result;
    }

    try {
      const content = await fs.readFile(filePath, "utf-8");
      const lines = content.split("\n");

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];

        for (const rule of this.config.customRules!) {
          if (rule.pattern.test(line)) {
            const message = {
              rule: rule.name,
              message: rule.message,
              file: filePath,
              line: i + 1,
              column: line.indexOf(line.match(rule.pattern)?.[0] || "") + 1,
              severity: rule.severity,
            };

            if (rule.severity === "error") {
              result.errors.push(message);
              result.isValid = false;
            } else {
              result.warnings.push(message);
            }
          }
        }
      }

      logger.debug(
        `Pattern validation completed for ${filePath}: ${result.errors.length} errors, ${result.warnings.length} warnings`
      );
    } catch (err) {
      const error = err instanceof Error ? err : new Error(String(err));
      logger.error(`Pattern validation failed for ${filePath}:`, error);
      result.errors.push({
        rule: "pattern-error",
        message: `Pattern validation failed: ${error.message}`,
        file: filePath,
        severity: "error",
      });
      result.isValid = false;
    }

    return result;
  }
}

/**
 * Validator registry and factory
 */
export class ValidatorRegistry {
  private validators: Map<string, BaseValidator> = new Map();

  /**
   * Register a validator
   */
  register(name: string, validator: BaseValidator): void {
    this.validators.set(name, validator);
    logger.info(`Validator registered: ${name}`);
  }

  /**
   * Get a validator by name
   */
  get(name: string): BaseValidator | undefined {
    return this.validators.get(name);
  }

  /**
   * Get all registered validators
   */
  getAll(): BaseValidator[] {
    return Array.from(this.validators.values());
  }

  /**
   * Validate a file with all applicable validators
   */
  async validateFile(filePath: string): Promise<ValidationResult> {
    const extension = Utils.getFileExtension(filePath);
    const result: ValidationResult = {
      isValid: true,
      errors: [],
      warnings: [],
    };

    for (const validator of this.validators.values()) {
      if (!validator.isEnabled()) {
        continue;
      }

      // Check if validator applies to this file type
      if (this.shouldValidateFile(validator.getName(), extension)) {
        try {
          const validatorResult = await validator.validate(filePath);

          result.errors.push(...validatorResult.errors);
          result.warnings.push(...validatorResult.warnings);

          if (!validatorResult.isValid) {
            result.isValid = false;
          }

          result.metadata = {
            ...result.metadata,
            [validator.getName()]: {
              isValid: validatorResult.isValid,
              errorCount: validatorResult.errors.length,
              warningCount: validatorResult.warnings.length,
            },
          };
        } catch (err) {
          const error = err instanceof Error ? err : new Error(String(err));
          logger.error(
            `Validator ${validator.getName()} failed for ${filePath}:`,
            error
          );
          result.errors.push({
            rule: "validator-error",
            message: `Validator ${validator.getName()} failed: ${
              error.message
            }`,
            file: filePath,
            severity: "error",
          });
          result.isValid = false;
        }
      }
    }

    return result;
  }

  /**
   * Check if a validator should be applied to a file type
   */
  private shouldValidateFile(
    validatorName: string,
    extension: string
  ): boolean {
    const validatorsByExtension: Record<string, string[]> = {
      js: ["eslint", "pattern"],
      jsx: ["eslint", "pattern"],
      ts: ["eslint", "pattern"],
      tsx: ["eslint", "pattern"],
      json: ["json"],
      yaml: ["yaml"],
      yml: ["yaml"],
      md: ["pattern"],
    };

    return validatorsByExtension[extension]?.includes(validatorName) || false;
  }
}

/**
 * Create default validator registry with common validators
 */
export function createValidatorRegistry(options?: {
  skipDefaults?: boolean;
}): ValidatorRegistry {
  const registry = new ValidatorRegistry();

  if (options?.skipDefaults) {
    return registry;
  }

  // Register default validators
  registry.register(
    "eslint",
    new ESLintValidator({
      enabled: true,
      rules: {},
    })
  );

  registry.register(
    "json",
    new JSONValidator({
      enabled: true,
      rules: {},
    })
  );

  registry.register(
    "yaml",
    new YAMLValidator({
      enabled: true,
      rules: {},
    })
  );

  registry.register(
    "pattern",
    new PatternValidator({
      enabled: true,
      rules: {},
      customRules: [
        {
          name: "console-log",
          pattern: /console\.log\(/,
          message: "Avoid console.log in production code",
          severity: "warning" as const,
        },
        {
          name: "todo-comment",
          pattern: /(TODO|FIXME|XXX)/i,
          message: "TODO comment found",
          severity: "warning" as const,
        },
      ],
    })
  );

  return registry;
}

export default BaseValidator;

import winston from "winston";
import path from "path";

// Define log levels
const logLevels = {
  error: 0,
  warn: 1,
  info: 2,
  http: 3,
  debug: 4,
};

// Define colors for different log levels
const logColors = {
  error: "red",
  warn: "yellow",
  info: "green",
  http: "magenta",
  debug: "white",
};

winston.addColors(logColors);

// Create the logger instance
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || "info",
  levels: logLevels,
  format: winston.format.combine(
    winston.format.timestamp({ format: "YYYY-MM-DD HH:mm:ss:ms" }),
    winston.format.colorize({ all: true }),
    winston.format.printf(({ timestamp, level, message, ...meta }) => {
      let metaStr = "";
      if (Object.keys(meta).length > 0) {
        metaStr = `\n${JSON.stringify(meta, null, 2)}`;
      }
      return `${timestamp} ${level}: ${message}${metaStr}`;
    })
  ),
  defaultMeta: { service: "watcher-service" },
  transports: [
    // Write all logs with importance level of `error` or less to `error.log`
    new winston.transports.File({
      filename: path.join(process.cwd(), "logs", "error.log"),
      level: "error",
      format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()
      ),
    }),
    // Write all logs with importance level of `info` or less to `combined.log`
    new winston.transports.File({
      filename: path.join(process.cwd(), "logs", "combined.log"),
      format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()
      ),
    }),
  ],
});

// If we're not in production then log to the console
if (process.env.NODE_ENV !== "production") {
  const logFormat =
    process.env.LOG_FORMAT === "json"
      ? winston.format.combine(
          winston.format.timestamp(),
          winston.format.json()
        )
      : winston.format.combine(
          winston.format.colorize(),
          winston.format.simple(),
          winston.format.printf(({ level, message, timestamp }) => {
            return `${timestamp} ${level}: ${message}`;
          })
        );

  logger.add(
    new winston.transports.Console({
      format: logFormat,
    })
  );
}

