import { CorrectorRegistry, createCorrectorRegistry } from "./correctors.js";
import {
  NotifierRegistry,
  createNotifierRegistry,
  NotificationUtils,
  NotificationLevel,
  NotificationChannel,
} from "./notifiers.js";
import {
  TriggerRuleManager,
  createTriggerRuleManager,
  TriggerContext,
  TriggerResult,
  TriggerRule,
} from "./rules.js";
import { Utils, safeSpawn } from "../shared/utils.js";
import { CircuitBreaker, retryWithBackoff } from "../shared/circuit-breaker.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("trigger");

/**
 * Trigger module configuration
 */
export interface TriggerModuleConfig {
  configPath?: string;
  enabled?: boolean;
  autoCorrect?: boolean;
  notifyOnFailure?: boolean;
  maxExecutionTime?: number;
  parallelExecution?: boolean;
}

/**
 * Main trigger module that orchestrates corrections and notifications
 */
export class TriggerModule {
  private ruleManager: TriggerRuleManager;
  private correctorRegistry: CorrectorRegistry;
  private notifierRegistry: NotifierRegistry;
  private config: TriggerModuleConfig;
  private isRunning: boolean = false;
  private circuitBreakers = new Map<string, CircuitBreaker>();

  constructor(
    config: TriggerModuleConfig = {},
    dependencies?: {
      ruleManager?: TriggerRuleManager;
      correctorRegistry?: CorrectorRegistry;
      notifierRegistry?: NotifierRegistry;
    }
  ) {
    this.config = {
      enabled: true,
      autoCorrect: true,
      notifyOnFailure: true,
      maxExecutionTime: 30000,
      parallelExecution: true,
      ...config,
    };

    // Initialize components (with dependency injection support)
    this.ruleManager =
      dependencies?.ruleManager || createTriggerRuleManager(config.configPath);
    this.correctorRegistry =
      dependencies?.correctorRegistry || createCorrectorRegistry();
    this.notifierRegistry =
      dependencies?.notifierRegistry || createNotifierRegistry();
  }

  /**
   * Start the trigger module
   */
  async start(): Promise<void> {
    if (this.isRunning) {
      logger.warn("Trigger module is already running");
      return;
    }

    try {
      logger.info("Starting trigger module...");

      this.isRunning = true;
      logger.info("Trigger module started successfully");
    } catch (error) {
      logger.error("Failed to start trigger module:", error);
      throw error;
    }
  }

  /**
   * Stop the trigger module
   */
  async stop(): Promise<void> {
    if (!this.isRunning) {
      logger.warn("Trigger module is not running");
      return;
    }

    try {
      logger.info("Stopping trigger module...");

      this.isRunning = false;
      logger.info("Trigger module stopped successfully");
    } catch (error) {
      logger.error("Failed to stop trigger module:", error);
      throw error;
    }
  }

  /**
   * Process a trigger event
   */
  async processEvent(context: TriggerContext): Promise<TriggerResult[]> {
    if (!this.isRunning || !this.config.enabled) {
      logger.debug("Trigger module is disabled or not running");
      return [];
    }

    try {
      logger.info(
        `Processing trigger event: ${context.eventType} for ${context.filePath}`
      );

      // Get applicable rules for this context
      const applicableRules = this.ruleManager.getApplicableRules(context);

      if (applicableRules.length === 0) {
        logger.debug(
          `No trigger rules applicable for event: ${context.eventType}`
        );
        return [];
      }

      logger.info(
        `Executing ${applicableRules.length} trigger rules for ${context.eventType}`
      );

      // Execute rules
      const results = await this.executeRules(applicableRules, context);

      // Update cooldowns for executed rules
      results.forEach((result) => {
        if (result.success && !result.skipped) {
          this.ruleManager.updateCooldown(result.ruleId);
        }
      });

      return results;
    } catch (error) {
      logger.error(`Error processing trigger event:`, error);

      // Send error notification if configured
      if (this.config.notifyOnFailure) {
        await this.sendErrorNotification(
          "Trigger Processing Error",
          error,
          context
        );
      }

      return [];
    }
  }

  /**
   * Execute multiple trigger rules
   */
  private async executeRules(
    rules: TriggerRule[],
    context: TriggerContext
  ): Promise<TriggerResult[]> {
    const results: TriggerResult[] = [];

    for (const rule of rules) {
      try {
        const result = await this.executeRule(rule, context);
        results.push(result);

        if (result.success) {
          logger.info(`Trigger rule ${rule.id} executed successfully`);
        } else {
          logger.warn(`Trigger rule ${rule.id} failed`);
        }
      } catch (error) {
        logger.error(`Error executing trigger rule ${rule.id}:`, error);
        results.push({
          ruleId: rule.id,
          success: false,
          actions: [],
          executionTime: 0,
          error: error instanceof Error ? error : new Error(String(error)),
        });
      }
    }

    return results;
  }

  /**
   * Execute a single trigger rule
   */
  private async executeRule(
    rule: TriggerRule,
    context: TriggerContext
  ): Promise<TriggerResult> {
    const startTime = Date.now();
    const result: TriggerResult = {
      ruleId: rule.id,
      success: true,
      actions: [],
      executionTime: 0,
    };

    try {
      // Execute each action in the rule
      for (const action of rule.actions) {
        try {
          // Apply delay if specified
          if (action.delay && action.delay > 0) {
            await Utils.sleep(action.delay);
          }

          const actionResult = await this.executeAction(action, context);
          result.actions.push(actionResult);

          if (!actionResult.success) {
            result.success = false;
          }
        } catch (error) {
          logger.error(`Error executing action ${action.type}:`, error);
          result.actions.push({
            type: action.type,
            success: false,
            error: error instanceof Error ? error : new Error(String(error)),
          });
          result.success = false;
        }
      }
    } catch (error) {
      logger.error(`Error in trigger rule ${rule.id}:`, error);
      result.success = false;
      result.actions.push({
        type: "rule-execution",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      });
    }

    result.executionTime = Date.now() - startTime;
    return result;
  }

  /**
   * Execute a single action
   */
  private async executeAction(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    try {
      switch (action.type) {
        case "correct":
          return await this.executeCorrection(action, context);

        case "notify":
          return await this.executeNotification(action, context);

        case "log":
          return await this.executeLogging(action, context);

        case "skip":
          return await this.executeSkip(action, context);

        case "custom":
          return await this.executeCustomAction(action, context);

        default:
          throw new Error(`Unknown action type: ${action.type}`);
      }
    } catch (error) {
      return {
        type: action.type,
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Execute correction action with retry and circuit breaker
   */
  private async executeCorrection(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    if (!this.config.autoCorrect) {
      return {
        type: "correct",
        success: true, // Skipped, not failed
        result: "Auto-correction disabled",
      };
    }

    try {
      const correctorName = action.target;
      if (!correctorName) {
        throw new Error("Corrector action missing target");
      }
      const corrector = this.correctorRegistry.get(correctorName);

      if (!corrector) {
        throw new Error(`Corrector not found: ${correctorName}`);
      }

      if (!corrector.isEnabled()) {
        return {
          type: "correct",
          success: true, // Skipped, not failed
          result: `Corrector ${correctorName} is disabled`,
        };
      }

      // Get or create circuit breaker for this corrector
      if (!this.circuitBreakers.has(correctorName)) {
        this.circuitBreakers.set(correctorName, new CircuitBreaker(5, 60000));
      }
      const circuitBreaker = this.circuitBreakers.get(correctorName)!;

      // Execute with retry + circuit breaker
      const correctionResults = await circuitBreaker.execute(() =>
        retryWithBackoff(
          () =>
            this.correctorRegistry.applyCorrections(
              context.filePath,
              context.error
            ),
          3,
          1000
        )
      );

      const success = correctionResults.every((result) => result.success);

      return {
        type: "correct",
        success,
        result: correctionResults,
      };
    } catch (error) {
      return {
        type: "correct",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Execute notification action
   */
  private async executeNotification(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    try {
      if (!action.target) {
        throw new Error("Notify action missing target channels");
      }
      const channels = action.target
        .split(",")
        .map((c: string) => c.trim()) as NotificationChannel[];
      const level =
        (action.config?.level as NotificationLevel) || NotificationLevel.INFO;

      // Create notification data based on context
      let notificationData;

      if (context.error) {
        const errorObj =
          context.error instanceof Error
            ? context.error
            : new Error(context.error.message);
        notificationData = NotificationUtils.createErrorNotification(
          `Trigger Rule: ${context.eventType}`,
          errorObj,
          context.filePath,
          { ruleId: context.metadata?.ruleId }
        );
      } else {
        notificationData = NotificationUtils.createFileNotification(
          `Trigger Rule: ${context.eventType}`,
          `File ${context.eventType}: ${context.filePath}`,
          context.filePath,
          level,
          { ruleId: context.metadata?.ruleId }
        );
      }

      const results = await this.notifierRegistry.sendToChannels(
        channels,
        notificationData
      );
      const success = results.every((result) => result.success);

      return {
        type: "notify",
        success,
        result: results,
      };
    } catch (error) {
      return {
        type: "notify",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Execute logging action
   */
  private async executeLogging(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    try {
      const logLevel = (action.config?.level as string) || "info";
      const message = `Trigger rule executed: ${context.eventType} for ${context.filePath}`;

      logger.log(logLevel, message, {
        ruleId: context.metadata?.ruleId,
        filePath: context.filePath,
        timestamp: context.timestamp,
      });

      return {
        type: "log",
        success: true,
        result: { level: logLevel, message },
      };
    } catch (error) {
      return {
        type: "log",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Execute skip action
   */
  private async executeSkip(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    try {
      // Check skip conditions
      if (action.config?.maxFileSize) {
        const stats = await Utils.fs.stat(context.filePath);
        const maxSizeBytes = Utils.parseFileSize(
          String(action.config.maxFileSize)
        );
        if (stats.size > maxSizeBytes) {
          logger.info(`Skipping file ${context.filePath} due to size limit`);
          return {
            type: "skip",
            success: true,
            result: {
              reason: "file-too-large",
              sizeLimit: action.config.maxFileSize,
            },
          };
        }
      }

      return {
        type: "skip",
        success: true,
        result: { reason: "skip-condition-met" },
      };
    } catch (error) {
      return {
        type: "skip",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Execute custom action
   */
  private async executeCustomAction(
    action: TriggerRule["actions"][number],
    context: TriggerContext
  ): Promise<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }> {
    try {
      const handler = action.config?.handler;
      const script = action.config?.script;

      if (handler && typeof handler === "function") {
        const result = await handler(context);
        return { type: "custom", success: true, result };
      }

      if (script && typeof script === "string") {
        // Whitelist: only allow known safe commands
        const allowedCommands = [
          "npx eslint",
          "npx prettier",
          "npm run",
          "node",
        ];
        const isAllowed = allowedCommands.some((cmd) =>
          script.trim().startsWith(cmd)
        );

        if (!isAllowed) {
          logger.warn(
            `Script not in whitelist, blocking: ${script.substring(0, 100)}`
          );
          return {
            type: "custom",
            success: false,
            error: new Error(
              `Script not allowed. Whitelist: ${allowedCommands.join(", ")}`
            ),
          };
        }

        // Parse command and args from script string safely
        const parts = script.split(/\s+/);
        const cmd = parts[0];
        const args = parts
          .slice(1)
          .map((a: string) =>
            a
              .replace(/\{\{filePath\}\}/g, context.filePath)
              .replace(/\{\{eventType\}\}/g, context.eventType)
          );

        logger.info(`Executing whitelisted script: ${cmd} ${args.join(" ")}`);
        const { stdout } = await safeSpawn(cmd, args, { timeout: 30000 });
        return { type: "custom", success: true, result: stdout.trim() };
      }

      throw new Error(
        "Custom action requires a config.handler function or config.script command"
      );
    } catch (error) {
      return {
        type: "custom",
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  /**
   * Send error notification
   */
  private async sendErrorNotification(
    title: string,
    error: unknown,
    context: TriggerContext
  ): Promise<void> {
    try {
      const notificationData = NotificationUtils.createErrorNotification(
        title,
        error instanceof Error ? error : new Error(String(error)),
        context.filePath,
        {
          eventType: context.eventType,
          timestamp: context.timestamp,
        }
      );

      await this.notifierRegistry.sendToAll(notificationData);
    } catch (notificationError) {
      logger.error("Failed to send error notification:", notificationError);
    }
  }

  /**
   * Get current status
   */
  getStatus(): {
    isRunning: boolean;
    enabled: boolean;
    ruleCount: number;
    enabledRuleCount: number;
    correctorCount: number;
    notifierCount: number;
    ruleStats: any;
  } {
    const ruleStats = this.ruleManager.getStats();

    return {
      isRunning: this.isRunning,
      enabled: this.config.enabled ?? true,
      ruleCount: ruleStats.totalRules,
      enabledRuleCount: ruleStats.enabledRules,
      correctorCount: this.correctorRegistry.getAll().length,
      notifierCount: this.notifierRegistry.getAll().length,
      ruleStats,
    };
  }

  /**
   * Reload configuration
   */
  async reloadConfig(): Promise<void> {
    await this.ruleManager.reloadConfig();
    logger.info("Trigger configuration reloaded");
  }

  /**
   * Add a custom rule
   */
  async addRule(rule: any): Promise<void> {
    await this.ruleManager.addRule(rule);
  }

  /**
   * Remove a rule
   */
  async removeRule(ruleId: string): Promise<boolean> {
    return await this.ruleManager.removeRule(ruleId);
  }

  /**
   * Toggle a rule
   */
  async toggleRule(ruleId: string, enabled: boolean): Promise<boolean> {
    return await this.ruleManager.toggleRule(ruleId, enabled);
  }
}

/**
 * Factory function to create a trigger module
 */
export function createTriggerModule(
  config?: TriggerModuleConfig,
  dependencies?: {
    ruleManager?: TriggerRuleManager;
    correctorRegistry?: CorrectorRegistry;
    notifierRegistry?: NotifierRegistry;
  }
): TriggerModule {
  return new TriggerModule(config, dependencies);
}

/**
 * Quick setup function for common use cases
 */
export async function setupTrigger(
  config?: TriggerModuleConfig
): Promise<TriggerModule> {
  const module = createTriggerModule(config);
  await module.start();
  return module;
}

export default TriggerModule;

import { WebClient } from "@slack/web-api";
import nodemailer from "nodemailer";
import fs from "fs-extra";
import path from "path";
import { escapeHtml } from "../shared/utils.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("trigger-notifiers");

/**
 * Notification level
 */
export enum NotificationLevel {
  INFO = "info",
  WARNING = "warning",
  ERROR = "error",
  SUCCESS = "success",
}

/**
 * Notification channel
 */
export enum NotificationChannel {
  SLACK = "slack",
  EMAIL = "email",
  CONSOLE = "console",
  FILE = "file",
}

/**
 * Notification data
 */
export interface NotificationData {
  title: string;
  message: string;
  level: NotificationLevel;
  channel: NotificationChannel;
  metadata?: Record<string, any>;
  file?: string;
  error?: Error;
  timestamp?: Date;
}

/**
 * Notification result
 */
export interface NotificationResult {
  success: boolean;
  channel: NotificationChannel;
  messageId?: string;
  error?: Error;
}

/**
 * Base notifier class
 */
export abstract class BaseNotifier {
  protected name: string;
  protected enabled: boolean;

  constructor(name: string, enabled: boolean = true) {
    this.name = name;
    this.enabled = enabled;
  }

  /**
   * Send a notification
   */
  abstract send(data: NotificationData): Promise<NotificationResult>;

  /**
   * Check if notifier is enabled
   */
  isEnabled(): boolean {
    return this.enabled;
  }

  /**
   * Get notifier name
   */
  getName(): string {
    return this.name;
  }

  /**
   * Enable/disable notifier
   */
  setEnabled(enabled: boolean): void {
    this.enabled = enabled;
  }
}

/**
 * Slack notifier
 */
export class SlackNotifier extends BaseNotifier {
  private client: WebClient;
  private defaultChannel: string;

  constructor(token?: string, channel?: string, enabled: boolean = true) {
    super("slack", enabled);
    this.client = new WebClient(token || process.env.SLACK_TOKEN);
    this.defaultChannel = channel || process.env.SLACK_CHANNEL || "#general";
  }

  async send(data: NotificationData): Promise<NotificationResult> {
    if (!this.isEnabled()) {
      return { success: true, channel: NotificationChannel.SLACK };
    }

    try {
      logger.info(`Sending Slack notification: ${data.title}`);

      const emoji = this.getLevelEmoji(data.level);

      const blocks: any[] = [
        {
          type: "header",
          text: {
            type: "plain_text",
            text: `${emoji} ${data.title}`,
          },
        },
        {
          type: "section",
          text: {
            type: "mrkdwn",
            text: data.message,
          },
        },
      ];

      // Add metadata if present
      if (data.metadata || data.file || data.error) {
        const fields: Array<{ type: "mrkdwn"; text: string }> = [];

        if (data.file) {
          fields.push({
            type: "mrkdwn",
            text: `*File:*\n${path.basename(data.file)}`,
          });
        }

        if (data.error) {
          fields.push({
            type: "mrkdwn",
            text: `*Error:*\n${data.error.message}`,
          });
        }

        if (data.metadata) {
          fields.push({
            type: "mrkdwn",
            text: `*Details:*\n${JSON.stringify(data.metadata, null, 2)}`,
          });
        }

        blocks.push({
          type: "section",
          fields,
        });
      }

      // Add timestamp
      blocks.push({
        type: "context",
        elements: [
          {
            type: "mrkdwn",
            text: `Triggered at ${new Date().toISOString()}`,
          },
        ],
      });

      const result = await this.client.chat.postMessage({
        channel: this.defaultChannel,
        blocks,
        text: `${data.title}: ${data.message}`, // Fallback text
      });

      logger.info(`Slack notification sent successfully: ${result.ts}`);

      return {
        success: true,
        channel: NotificationChannel.SLACK,
        messageId: result.ts,
      };
    } catch (error) {
      logger.error("Failed to send Slack notification:", error);
      return {
        success: false,
        channel: NotificationChannel.SLACK,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  private getLevelEmoji(level: NotificationLevel): string {
    switch (level) {
      case NotificationLevel.ERROR:
        return "ÔØî";
      case NotificationLevel.WARNING:
        return "ÔÜá´©Å";
      case NotificationLevel.SUCCESS:
        return "Ô£à";
      case NotificationLevel.INFO:
      default:
        return "Ôä╣´©Å";
    }
  }

  private getLevelColor(level: NotificationLevel): string {
    switch (level) {
      case NotificationLevel.ERROR:
        return "#ff0000";
      case NotificationLevel.WARNING:
        return "#ffa500";
      case NotificationLevel.SUCCESS:
        return "#00ff00";
      case NotificationLevel.INFO:
      default:
        return "#0099ff";
    }
  }
}

/**
 * Email notifier
 */
export class EmailNotifier extends BaseNotifier {
  private transporter: nodemailer.Transporter;
  private from: string;
  private to: string;

  constructor(
    smtpConfig?: {
      host?: string;
      port?: number;
      secure?: boolean;
      user?: string;
      pass?: string;
    },
    from?: string,
    to?: string,
    enabled: boolean = true
  ) {
    super("email", enabled);

    const config = {
      host: smtpConfig?.host || process.env.EMAIL_HOST || "smtp.gmail.com",
      port: smtpConfig?.port || parseInt(process.env.EMAIL_PORT || "587"),
      secure: smtpConfig?.secure || false,
      auth: {
        user: smtpConfig?.user || process.env.EMAIL_USER,
        pass: smtpConfig?.pass || process.env.EMAIL_PASS,
      },
    };

    this.transporter = nodemailer.createTransport(config);
    this.from = from || process.env.EMAIL_FROM || "watcher@localhost";
    this.to = to || process.env.EMAIL_TO || "";
  }

  async send(data: NotificationData): Promise<NotificationResult> {
    if (!this.isEnabled()) {
      return { success: true, channel: NotificationChannel.EMAIL };
    }

    try {
      logger.info(`Sending email notification: ${data.title}`);

      const subject = `[${data.level.toUpperCase()}] ${data.title}`;
      const html = this.formatHtml(data);
      const text = this.formatText(data);

      const result = await this.transporter.sendMail({
        from: this.from,
        to: this.to,
        subject,
        text,
        html,
      });

      logger.info(`Email notification sent successfully: ${result.messageId}`);

      return {
        success: true,
        channel: NotificationChannel.EMAIL,
        messageId: result.messageId,
      };
    } catch (error) {
      logger.error("Failed to send email notification:", error);
      return {
        success: false,
        channel: NotificationChannel.EMAIL,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  private formatHtml(data: NotificationData): string {
    const level = data.level.toUpperCase();
    const fileInfo = data.file
      ? `<p><strong>File:</strong> ${escapeHtml(path.basename(data.file))}</p>`
      : "";
    const errorInfo = data.error
      ? `<p><strong>Error:</strong> ${escapeHtml(data.error.message)}</p>`
      : "";
    const metadataInfo = data.metadata
      ? `<p><strong>Details:</strong><pre>${escapeHtml(
          JSON.stringify(data.metadata, null, 2)
        )}</pre></p>`
      : "";

    return `
      <html>
        <body>
          <h2 style="color: ${this.getLevelColor(data.level)};">[${escapeHtml(
      level
    )}] ${escapeHtml(data.title)}</h2>
          <p>${escapeHtml(data.message)}</p>
          ${fileInfo}
          ${errorInfo}
          ${metadataInfo}
          <hr>
          <small>Triggered at ${new Date().toISOString()}</small>
        </body>
      </html>
    `;
  }

  private formatText(data: NotificationData): string {
    let text = `[${data.level.toUpperCase()}] ${data.title}\n\n`;
    text += `${data.message}\n\n`;

    if (data.file) {
      text += `File: ${path.basename(data.file)}\n`;
    }

    if (data.error) {
      text += `Error: ${data.error.message}\n`;
    }

    if (data.metadata) {
      text += `Details: ${JSON.stringify(data.metadata, null, 2)}\n`;
    }

    text += `\nTriggered at ${new Date().toISOString()}`;

    return text;
  }

  private getLevelColor(level: NotificationLevel): string {
    switch (level) {
      case NotificationLevel.ERROR:
        return "#ff0000";
      case NotificationLevel.WARNING:
        return "#ffa500";
      case NotificationLevel.SUCCESS:
        return "#00ff00";
      case NotificationLevel.INFO:
      default:
        return "#0099ff";
    }
  }
}

/**
 * Console notifier
 */
export class ConsoleNotifier extends BaseNotifier {
  constructor(enabled: boolean = true) {
    super("console", enabled);
  }

  async send(data: NotificationData): Promise<NotificationResult> {
    if (!this.isEnabled()) {
      return { success: true, channel: NotificationChannel.CONSOLE };
    }

    try {
      const emoji = this.getLevelEmoji(data.level);
      const level = data.level.toUpperCase();
      const fileInfo = data.file ? ` | File: ${path.basename(data.file)}` : "";
      const errorInfo = data.error ? ` | Error: ${data.error.message}` : "";

      const message = `${emoji} [${level}] ${data.title}: ${data.message}${fileInfo}${errorInfo}`;

      switch (data.level) {
        case NotificationLevel.ERROR:
          logger.error(message);
          break;
        case NotificationLevel.WARNING:
          logger.warn(message);
          break;
        case NotificationLevel.SUCCESS:
          logger.info(message);
          break;
        case NotificationLevel.INFO:
        default:
          logger.info(message);
          break;
      }

      return {
        success: true,
        channel: NotificationChannel.CONSOLE,
      };
    } catch (error) {
      logger.error("Failed to send console notification:", error);
      return {
        success: false,
        channel: NotificationChannel.CONSOLE,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }

  private getLevelEmoji(level: NotificationLevel): string {
    switch (level) {
      case NotificationLevel.ERROR:
        return "ÔØî";
      case NotificationLevel.WARNING:
        return "ÔÜá´©Å";
      case NotificationLevel.SUCCESS:
        return "Ô£à";
      case NotificationLevel.INFO:
      default:
        return "Ôä╣´©Å";
    }
  }
}

/**
 * File notifier (logs to file)
 */
export class FileNotifier extends BaseNotifier {
  private logPath: string;

  constructor(logPath?: string, enabled: boolean = true) {
    super("file", enabled);
    this.logPath =
      logPath || path.join(process.cwd(), "logs", "notifications.log");
  }

  async send(data: NotificationData): Promise<NotificationResult> {
    if (!this.isEnabled()) {
      return { success: true, channel: NotificationChannel.FILE };
    }

    try {
      await fs.ensureDir(path.dirname(this.logPath));

      const logEntry = {
        timestamp: new Date().toISOString(),
        level: data.level,
        channel: data.channel,
        title: data.title,
        message: data.message,
        file: data.file,
        error: data.error?.message,
        metadata: data.metadata,
      };

      const logLine = JSON.stringify(logEntry) + "\n";
      await fs.appendFile(this.logPath, logLine);

      logger.debug(`Notification logged to file: ${this.logPath}`);

      return {
        success: true,
        channel: NotificationChannel.FILE,
      };
    } catch (error) {
      logger.error("Failed to send file notification:", error);
      return {
        success: false,
        channel: NotificationChannel.FILE,
        error: error instanceof Error ? error : new Error(String(error)),
      };
    }
  }
}

/**
 * Notifier registry and manager
 */
export class NotifierRegistry {
  private notifiers: Map<NotificationChannel, BaseNotifier> = new Map();

  /**
   * Register a notifier
   */
  register(channel: NotificationChannel, notifier: BaseNotifier): void {
    this.notifiers.set(channel, notifier);
    logger.info(`Notifier registered for channel: ${channel}`);
  }

  /**
   * Get a notifier by channel
   */
  get(channel: NotificationChannel): BaseNotifier | undefined {
    return this.notifiers.get(channel);
  }

  /**
   * Get all registered notifiers
   */
  getAll(): BaseNotifier[] {
    return Array.from(this.notifiers.values());
  }

  /**
   * Send notification to a specific channel
   */
  async sendToChannel(
    channel: NotificationChannel,
    data: NotificationData
  ): Promise<NotificationResult> {
    const notifier = this.get(channel);
    if (!notifier) {
      return {
        success: false,
        channel,
        error: new Error(`No notifier registered for channel: ${channel}`),
      };
    }

    return await notifier.send(data);
  }

  /**
   * Send notification to multiple channels
   */
  async sendToChannels(
    channels: NotificationChannel[],
    data: NotificationData
  ): Promise<NotificationResult[]> {
    const results = await Promise.allSettled(
      channels.map((channel) => this.sendToChannel(channel, data))
    );

    return results.map((result, index) => {
      if (result.status === "fulfilled") {
        return result.value;
      } else {
        return {
          success: false,
          channel: channels[index],
          error: result.reason,
        };
      }
    });
  }

  /**
   * Send notification to all registered channels
   */
  async sendToAll(data: NotificationData): Promise<NotificationResult[]> {
    const channels = Array.from(this.notifiers.keys());
    return this.sendToChannels(channels, data);
  }
}

/**
 * Create default notifier registry with common notifiers
 */
export function createNotifierRegistry(options?: {
  skipDefaults?: boolean;
}): NotifierRegistry {
  const registry = new NotifierRegistry();

  if (options?.skipDefaults) {
    return registry;
  }

  // Register default notifiers
  registry.register(NotificationChannel.SLACK, new SlackNotifier());
  registry.register(NotificationChannel.EMAIL, new EmailNotifier());
  registry.register(NotificationChannel.CONSOLE, new ConsoleNotifier());
  registry.register(NotificationChannel.FILE, new FileNotifier());

  return registry;
}

/**
 * Notification utility functions
 */
export class NotificationUtils {
  /**
   * Create notification data for file events
   */
  static createFileNotification(
    title: string,
    message: string,
    filePath: string,
    level: NotificationLevel = NotificationLevel.INFO,
    metadata?: Record<string, any>
  ): NotificationData {
    return {
      title,
      message,
      level,
      channel: NotificationChannel.CONSOLE, // Default channel
      file: filePath,
      metadata,
      timestamp: new Date(),
    };
  }

  /**
   * Create notification data for errors
   */
  static createErrorNotification(
    title: string,
    error: Error,
    filePath?: string,
    metadata?: Record<string, any>
  ): NotificationData {
    return {
      title,
      message: error.message,
      level: NotificationLevel.ERROR,
      channel: NotificationChannel.CONSOLE, // Default channel
      file: filePath,
      error,
      metadata,
      timestamp: new Date(),
    };
  }

  /**
   * Create notification data for correction results
   */
  static createCorrectionNotification(
    title: string,
    correctedFiles: string[],
    failedFiles: string[],
    metadata?: Record<string, any>
  ): NotificationData {
    const totalFiles = correctedFiles.length + failedFiles.length;
    const successRate =
      totalFiles > 0
        ? ((correctedFiles.length / totalFiles) * 100).toFixed(1)
        : "0";

    let message = `Processed ${totalFiles} files. `;
    message += `Success rate: ${successRate}%. `;

    if (correctedFiles.length > 0) {
      message += `Corrected: ${correctedFiles.join(", ")}. `;
    }

    if (failedFiles.length > 0) {
      message += `Failed: ${failedFiles.join(", ")}.`;
    }

    return {
      title,
      message,
      level:
        failedFiles.length > 0
          ? NotificationLevel.WARNING
          : NotificationLevel.SUCCESS,
      channel: NotificationChannel.CONSOLE, // Default channel
      metadata: {
        ...metadata,
        correctedFiles,
        failedFiles,
        totalFiles,
        successRate: `${successRate}%`,
      },
      timestamp: new Date(),
    };
  }
}

export default BaseNotifier;

import fs from "fs-extra";
import path from "path";
import Joi from "joi";
import { Utils } from "../shared/utils.js";
import { createChildLogger } from "../shared/logger.js";

const logger = createChildLogger("trigger-rules");

export interface TriggerRule {
  id: string;
  name: string;
  description: string;
  enabled: boolean;
  priority: number;
  conditions: {
    eventTypes?: string[];
    fileExtensions?: string[];
    filePatterns?: string[];
    errorPatterns?: string[];
    severity?: "error" | "warning" | "info";
    metadataConditions?: Record<string, unknown>;
  };
  actions: Array<{
    type: "correct" | "notify" | "log" | "skip" | "custom";
    target?: string;
    config?: Record<string, unknown>;
    delay?: number;
  }>;
  cooldown?: {
    enabled: boolean;
    period: number;
  };
  metadata?: Record<string, unknown>;
}

export interface TriggerContext {
  filePath: string;
  eventType: string;
  error?: Error | { message: string; [key: string]: unknown };
  metadata?: Record<string, unknown>;
  timestamp: Date;
}

export interface TriggerResult {
  ruleId: string;
  success: boolean;
  actions: Array<{
    type: string;
    success: boolean;
    result?: string | unknown[] | Record<string, unknown>;
    error?: Error;
  }>;
  executionTime: number;
  skipped?: boolean;
  cooldown?: boolean;
  error?: Error;
}

export class TriggerRuleManager {
  private rules: TriggerRule[] = [];
  private configPath: string;
  private configSchema: Joi.ObjectSchema;
  private cooldowns: Map<string, number> = new Map();

  constructor(configPath?: string) {
    this.configPath =
      configPath || path.join(process.cwd(), "config", "trigger-rules.json");

    this.configSchema = Joi.object({
      rules: Joi.array()
        .items(
          Joi.object({
            id: Joi.string().required(),
            name: Joi.string().required(),
            description: Joi.string().required(),
            enabled: Joi.boolean().default(true),
            priority: Joi.number().default(0),
            conditions: Joi.object({
              eventTypes: Joi.array().items(Joi.string()),
              fileExtensions: Joi.array().items(Joi.string()),
              filePatterns: Joi.array().items(Joi.string()),
              errorPatterns: Joi.array().items(Joi.string()),
              severity: Joi.string().valid("error", "warning", "info"),
              metadataConditions: Joi.object().default({}),
            }).default(),
            actions: Joi.array()
              .items(
                Joi.object({
                  type: Joi.string()
                    .valid("correct", "notify", "log", "skip", "custom")
                    .required(),
                  target: Joi.string(),
                  config: Joi.object().default({}),
                  delay: Joi.number().default(0),
                })
              )
              .default([]),
            cooldown: Joi.object({
              enabled: Joi.boolean().default(false),
              period: Joi.number().default(60000),
            }).default(),
          })
        )
        .default([]),
    });

    this.loadConfig();
  }

  private loadConfig(): void {
    try {
      if (fs.pathExistsSync(this.configPath)) {
        const raw = fs.readJsonSync(this.configPath);

        if (raw.rules) {
          const { error, value } = this.configSchema.validate(raw, {
            allowUnknown: true,
          });
          if (error) {
            logger.warn(
              `Configuration validation error: ${error.message}. Using defaults.`
            );
          } else {
            this.rules = value.rules || [];
            logger.info(
              `Loaded ${this.rules.length} trigger rules from configuration`
            );
            return;
          }
        } else if (raw.corrections) {
          const rules = this.convertLegacyConfig(raw);
          const { error, value } = this.configSchema.validate(
            { rules },
            { allowUnknown: true }
          );
          if (error) {
            logger.warn(
              `Converted legacy config validation error: ${error.message}. Using defaults.`
            );
          } else {
            this.rules = value.rules || [];
            logger.info(
              `Converted and loaded ${this.rules.length} trigger rules from legacy configuration`
            );
            return;
          }
        }
      }
    } catch (error) {
      logger.error("Error loading trigger rules configuration:", error);
    }

    logger.info("Using default trigger rules");
    this.loadDefaultRules();
  }

  private convertLegacyConfig(raw: any): TriggerRule[] {
    const rules: TriggerRule[] = [];
    const corrections = raw.corrections || [];
    const conditions = raw.conditions || [];
    const notifications = raw.notifications || {};

    const conditionMap = new Map<string, any>();
    for (const cond of conditions) {
      conditionMap.set(cond.name, cond);
    }

    for (const corr of corrections) {
      const rule: TriggerRule = {
        id: corr.ruleId,
        name: corr.description || corr.ruleId,
        description: corr.description || "",
        enabled: corr.enabled !== false,
        priority: 1,
        conditions: {},
        actions: [],
      };

      if (corr.extensions) {
        rule.conditions.fileExtensions = corr.extensions;
      }

      switch (corr.action) {
        case "remove":
          rule.actions.push({
            type: "correct",
            target: "text-replacement",
            config: {
              type: "delete",
              target: "all",
              content: corr.pattern || "",
            },
          });
          break;
        case "replace":
          rule.actions.push({
            type: "correct",
            target: "text-replacement",
            config: {
              type: "replace",
              target: "all",
              content: corr.pattern || "",
              newText: corr.replacement || "",
            },
          });
          break;
        case "merge":
          rule.actions.push({
            type: "custom",
            config: {
              handler: "merge-duplicate-imports",
            },
          });
          break;
        case "run-eslint-fix":
          rule.actions.push({
            type: "correct",
            target: "eslint-fix",
            delay: 100,
          });
          break;
        case "run-prettier":
          rule.actions.push({
            type: "correct",
            target: "prettier-format",
            delay: 50,
          });
          break;
        default:
          rule.actions.push({
            type: "correct",
            target: "text-replacement",
            config: {
              type: "replace",
              target: "all",
              content: corr.pattern || "",
              newText: corr.replacement || "",
            },
          });
      }

      if (notifications.onFailure !== false) {
        const notifyAction: any = {
          type: "notify",
          target: "slack,email",
          config: { level: "warning" },
        };
        if (Array.isArray(notifications.channels)) {
          notifyAction.target = notifications.channels.join(",");
        }
        if (notifications.throttle) {
          rule.cooldown = { enabled: true, period: notifications.throttle };
        }
        rule.actions.push(notifyAction);
      }

      for (const cond of conditions) {
        if (cond.name === "file-too-large" && cond.action === "skip") {
          rule.actions.unshift({
            type: "skip",
            config: { maxFileSize: raw.autoCorrect?.maxFileSize || "1MB" },
          });
        }
      }

      rules.push(rule);
    }

    return rules;
  }

  private loadDefaultRules(): void {
    this.rules = [
      {
        id: "auto-correct-eslint",
        name: "Auto-correct ESLint errors",
        description:
          "Automatically fix ESLint errors in JavaScript/TypeScript files",
        enabled: true,
        priority: 10,
        conditions: {
          eventTypes: ["fileModified"],
          fileExtensions: ["js", "ts", "jsx", "tsx"],
          errorPatterns: ["eslint"],
        },
        actions: [
          {
            type: "correct",
            target: "eslint-fix",
            delay: 100,
          },
        ],
      },
      {
        id: "format-with-prettier",
        name: "Format with Prettier",
        description: "Format supported files with Prettier",
        enabled: true,
        priority: 5,
        conditions: {
          eventTypes: ["fileModified"],
          fileExtensions: [
            "js",
            "ts",
            "jsx",
            "tsx",
            "json",
            "md",
            "css",
            "scss",
          ],
        },
        actions: [
          {
            type: "correct",
            target: "prettier-format",
            delay: 50,
          },
        ],
      },
      {
        id: "notify-on-correction-failure",
        name: "Notify on correction failure",
        description: "Send notification when automatic corrections fail",
        enabled: true,
        priority: 1,
        conditions: {
          eventTypes: ["correctionFailed"],
          severity: "error",
        },
        actions: [
          {
            type: "notify",
            target: "slack,email",
            config: {
              level: "error",
            },
          },
        ],
      },
      {
        id: "log-file-changes",
        name: "Log file changes",
        description: "Log all file changes for audit purposes",
        enabled: true,
        priority: 0,
        conditions: {
          eventTypes: ["fileModified", "fileAdded", "fileDeleted"],
        },
        actions: [
          {
            type: "log",
            config: {
              level: "info",
            },
          },
        ],
      },
      {
        id: "skip-large-files",
        name: "Skip large files",
        description:
          "Skip processing very large files to avoid performance issues",
        enabled: true,
        priority: 100,
        conditions: {
          eventTypes: ["fileModified"],
        },
        actions: [
          {
            type: "skip",
            config: {
              maxFileSize: 5 * 1024 * 1024,
            },
          },
        ],
      },
    ];
    logger.info(`Loaded ${this.rules.length} default trigger rules`);
  }

  getRules(): TriggerRule[] {
    return [...this.rules];
  }

  getEnabledRules(): TriggerRule[] {
    return this.rules.filter((rule) => rule.enabled);
  }

  getApplicableRules(context: TriggerContext): TriggerRule[] {
    const enabledRules = this.getEnabledRules();
    return enabledRules
      .filter((rule) => this.ruleMatchesContext(rule, context))
      .sort((a, b) => b.priority - a.priority);
  }

  private ruleMatchesContext(
    rule: TriggerRule,
    context: TriggerContext
  ): boolean {
    if (rule.conditions.eventTypes) {
      if (!rule.conditions.eventTypes.includes(context.eventType)) {
        return false;
      }
    }

    if (rule.conditions.fileExtensions) {
      const extension = Utils.getFileExtension(context.filePath);
      if (!rule.conditions.fileExtensions.includes(extension)) {
        return false;
      }
    }

    if (rule.conditions.filePatterns) {
      const fileName = path.basename(context.filePath);
      const matchesPattern = rule.conditions.filePatterns.some(
        (pattern) =>
          fileName.includes(pattern) || context.filePath.includes(pattern)
      );
      if (!matchesPattern) {
        return false;
      }
    }

    if (rule.conditions.errorPatterns && context.error) {
      const errorMessage = context.error.message || String(context.error);
      const matchesErrorPattern = rule.conditions.errorPatterns.some(
        (pattern) => errorMessage.includes(pattern)
      );
      if (!matchesErrorPattern) {
        return false;
      }
    }

    if (rule.conditions.severity && context.metadata?.severity) {
      if (rule.conditions.severity !== context.metadata.severity) {
        return false;
      }
    }

    if (rule.conditions.metadataConditions) {
      for (const [key, value] of Object.entries(
        rule.conditions.metadataConditions
      )) {
        if (context.metadata?.[key] !== value) {
          return false;
        }
      }
    }

    if (rule.cooldown?.enabled) {
      const lastExecution = this.cooldowns.get(rule.id) || 0;
      const now = Date.now();
      const cooldownPeriod = rule.cooldown.period;
      if (now - lastExecution < cooldownPeriod) {
        return false;
      }
    }

    return true;
  }

  async addRule(rule: TriggerRule): Promise<void> {
    const existingIndex = this.rules.findIndex((r) => r.id === rule.id);
    if (existingIndex >= 0) {
      this.rules[existingIndex] = rule;
    } else {
      this.rules.push(rule);
    }

    await this.saveConfig();
    logger.info(`Trigger rule added/updated: ${rule.id}`);
  }

  async removeRule(ruleId: string): Promise<boolean> {
    const initialLength = this.rules.length;
    this.rules = this.rules.filter((rule) => rule.id !== ruleId);
    if (this.rules.length < initialLength) {
      await this.saveConfig();
      logger.info(`Trigger rule removed: ${ruleId}`);
      return true;
    }
    return false;
  }

  async toggleRule(ruleId: string, enabled: boolean): Promise<boolean> {
    const rule = this.rules.find((r) => r.id === ruleId);
    if (rule) {
      rule.enabled = enabled;
      await this.saveConfig();
      logger.info(`Trigger rule ${ruleId} ${enabled ? "enabled" : "disabled"}`);
      return true;
    }
    return false;
  }

  updateCooldown(ruleId: string): void {
    this.cooldowns.set(ruleId, Date.now());
  }

  getStats(): {
    totalRules: number;
    enabledRules: number;
    rulesByPriority: Record<string, number>;
    activeCooldowns: number;
  } {
    const enabledRules = this.getEnabledRules();
    const rulesByPriority: Record<string, number> = {};

    this.rules.forEach((rule) => {
      const priorityRange = `${Math.floor(rule.priority / 10) * 10}-${
        Math.floor(rule.priority / 10) * 10 + 9
      }`;
      rulesByPriority[priorityRange] =
        (rulesByPriority[priorityRange] || 0) + 1;
    });

    return {
      totalRules: this.rules.length,
      enabledRules: enabledRules.length,
      rulesByPriority,
      activeCooldowns: this.cooldowns.size,
    };
  }

  async saveConfig(): Promise<void> {
    try {
      await Utils.writeJsonFile(this.configPath, { rules: this.rules });
    } catch (error) {
      logger.error("Error saving trigger rules configuration:", error);
      throw error;
    }
  }

  async reloadConfig(): Promise<void> {
    this.cooldowns.clear();
    this.loadConfig();
    logger.info("Trigger rules configuration reloaded");
  }

  exportConfig(): { rules: TriggerRule[] } {
    return { rules: JSON.parse(JSON.stringify(this.rules)) };
  }

  async importConfig(config: { rules: TriggerRule[] }): Promise<void> {
    const { error } = this.configSchema.validate(config);
    if (error) {
      throw new Error(`Invalid configuration: ${error.message}`);
    }
    this.rules = config.rules;
    await this.saveConfig();
    logger.info("Trigger rules configuration imported successfully");
  }
}

export function createTriggerRuleManager(
  configPath?: string
): TriggerRuleManager {
  return new TriggerRuleManager(configPath);
}

export default TriggerRuleManager;
